window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[3]=[{"id":100700101,"themeId":3,"group":1007001,"chapter":7,"chapters":[7],"q":"В каком случае сигналы регулировщика обязательны для исполнения участниками дорожного движения?","a":["Только в случае, если они соответствуют сигналам светофоров и других технических средств организации дорожного движения.","Во всех случаях, даже если они не соответствуют сигналам светофоров и других технических средств организации дорожного движения."],"c":1,"e":"<p>Сигналы регулировщика обязательны для исполнения участниками дорожного движения во всех случаях, даже если они не соответствуют сигналам светофоров и других технических средств организации дорожного движения.</p>","image":null},{"id":100700102,"themeId":3,"group":1007001,"chapter":7,"chapters":[7],"q":"Обязательны ли для исполнения участниками дорожного движения сигналы регулировщика?","a":["Обязательны только для водителей транспортных средств.","Обязательны только для водителей механических транспортных средств.","Обязательны для исполнения всеми участниками дорожного движения."],"c":2,"e":"<p>Сигналы регулировщика обязательны для исполнения всеми участниками дорожного движения.</p>","image":null},{"id":100700201,"themeId":3,"group":1007002,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение прямо или направо.</p>","image":"assets/adrive-questions/q100700201.jpg"},{"id":100700202,"themeId":3,"group":1007002,"chapter":7,"chapters":[7],"q":"Разрешается ли водителю легкового автомобиля в показанной ситуации повернуть направо?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение прямо и направо, поэтому водителю легкового автомобиля разрешено повернуть направо.</p>","image":"assets/adrive-questions/q100700202.jpg"},{"id":100700203,"themeId":3,"group":1007002,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение синему (прямо) и красному (направо) автомобилям.</p>","image":"assets/adrive-questions/q100700203.jpg"},{"id":100700301,"themeId":3,"group":1007003,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика разрешает продолжить движение во всех направлениях.</p>","image":"assets/adrive-questions/q100700301.jpg"},{"id":100700302,"themeId":3,"group":1007003,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает продолжить движение синему и красному автомобилям в намеченных направлениях.</p>","image":"assets/adrive-questions/q100700302.jpg"},{"id":100700401,"themeId":3,"group":1007004,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение во всех направлениях.</p>","image":"assets/adrive-questions/q100700401.jpg"},{"id":100700402,"themeId":3,"group":1007004,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение обоим автомобилям.</p>","image":"assets/adrive-questions/q100700402.jpg"},{"id":100700501,"themeId":3,"group":1007005,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение во всех направлениях.</p>","image":"assets/adrive-questions/q100700501.jpg"},{"id":100700502,"themeId":3,"group":1007005,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение обоим автомобилям.</p>","image":"assets/adrive-questions/q100700502.jpg"},{"id":100700601,"themeId":3,"group":1007006,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает продолжить движение через перекрёсток с показанного направления.</p>","image":"assets/adrive-questions/q100700601.jpg"},{"id":100700602,"themeId":3,"group":1007006,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только автобусу.","Только чёрному легковому автомобилю.","Чёрному и синему легковым автомобилям.","Чёрному легковому автомобилю и автобусу.","Движение всем транспортным средствам в показанной ситуации разрешено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение чёрному легковому автомобилю и автобусу в намеченных направлениях. Движение красному и синему легковому автомобилям запрещено.</p>","image":"assets/adrive-questions/q100700602.jpg"},{"id":100700701,"themeId":3,"group":1007007,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение через перекрёсток с показанного направления.</p>","image":"assets/adrive-questions/q100700701.jpg"},{"id":100700702,"themeId":3,"group":1007007,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение водителям обоих автомобилей.</p>","image":"assets/adrive-questions/q100700702.jpg"},{"id":100700801,"themeId":3,"group":1007008,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение с показанного направления только направо.</p>","image":"assets/adrive-questions/q100700801.jpg"},{"id":100700802,"themeId":3,"group":1007008,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Движение всем транспортным средствам в показанной ситуации разрешено.","Движение всем транспортным средствам в показанной ситуации запрещено."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение только водителю красного автомобиля направо. Водителю синего автомобиля движение прямо запрещено.</p>","image":"assets/adrive-questions/q100700802.jpg"},{"id":100700901,"themeId":3,"group":1007009,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает Вам продолжить движение во всех направлениях.</p>","image":"assets/adrive-questions/q100700901.jpg"},{"id":100700902,"themeId":3,"group":1007009,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителям обоих автомобилей продолжить движение в намеченных направлениях.</p>","image":"assets/adrive-questions/q100700902.jpg"},{"id":100701001,"themeId":3,"group":1007010,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает продолжить движение во всех направлениях.</p>","image":"assets/adrive-questions/q100701001.jpg"},{"id":100701002,"themeId":3,"group":1007010,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено продолжить движение в показанной ситуации?","a":["Только синему автомобилю.","Только красному автомобилю.","Синему и красному автомобилям.","Движение обоим автомобилям в показанной ситуации запрещено."],"c":3,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителям обоих автомобилей продолжить движение в намеченных направлениях.</p>","image":"assets/adrive-questions/q100701002.jpg"},{"id":100701101,"themeId":3,"group":1007011,"chapter":7,"chapters":[7],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только прямо.","Только направо.","Прямо или направо.","Во всех направлениях.","Движение в показанной ситуации запрещено."],"c":4,"e":"<p>В показанной ситуации сигнал регулировщика запрещает продолжить движение во всех направлениях.</p>","image":"assets/adrive-questions/q100701101.jpg"},{"id":100701201,"themeId":3,"group":1007012,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля при повороте направо в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая.","Разрешено продолжать движение в намеченном направлении только после проезда грузового автомобиля.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая и грузового автомобиля."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля продолжить движение направо, при этом водителю грузового автомобиля разрешено продолжить движение только направо. Трамваю движение запрещено.</p>","image":"assets/adrive-questions/q100701201.jpg"},{"id":100701202,"themeId":3,"group":1007012,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая.","Разрешено продолжать движение в намеченном направлении только после проезда автобуса.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая и автобуса."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение легковому автомобилю в намеченном направлении (прямо), а водителям трамвая и автобуса движение запрещено.</p>","image":"assets/adrive-questions/q100701202.jpg"},{"id":100701301,"themeId":3,"group":1007013,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля продолжить движение в намеченном направлении (прямо), при этом водителю трамвая запрещено продолжить движение направо.</p>","image":"assets/adrive-questions/q100701301.jpg"},{"id":100701302,"themeId":3,"group":1007013,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля, намеревающемуся повернуть налево, в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля продолжить движение в намеченном направлении, при этом водителю трамвая запрещено продолжить движение прямо.</p>","image":"assets/adrive-questions/q100701302.jpg"},{"id":100701401,"themeId":3,"group":1007014,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение легковому автомобилю в намеченном направлении, а водителю трамвая движение запрещено.</p>","image":"assets/adrive-questions/q100701401.jpg"},{"id":100701402,"themeId":3,"group":1007014,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение легковому автомобилю в намеченном направлении (прямо), а водителю трамвая движение запрещено.</p>","image":"assets/adrive-questions/q100701402.jpg"},{"id":100701501,"themeId":3,"group":1007015,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля при повороте направо в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля продолжить движение в намеченном направлении, при этом водителю трамвая запрещено продолжить движение прямо.</p>","image":"assets/adrive-questions/q100701501.jpg"},{"id":100701502,"themeId":3,"group":1007015,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Запрещено продолжать движение прямо.","Разрешено продолжать движение прямо, уступив дорогу трамваю.","Разрешено продолжать движение прямо, уступив дорогу автобусу.","Разрешено продолжать движение прямо, уступив дорогу автобусу и трамваю."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителю легкового автомобиля и трамвая продолжить движение в намеченных направлениях, при этом водителю автобуса разрешено продолжить движение прямо.</p>","image":"assets/adrive-questions/q100701502.jpg"},{"id":100701601,"themeId":3,"group":1007016,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля, намеревающемуся повернуть налево, в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика запрещает движение легковому автомобилю в намеченном направлении.</p>","image":"assets/adrive-questions/q100701601.jpg"},{"id":100701602,"themeId":3,"group":1007016,"chapter":7,"chapters":[7],"q":"Водителю легкового автомобиля в показанной ситуации:","a":["Разрешено продолжать движение в намеченном направлении.","Запрещено продолжать движение в намеченном направлении.","Разрешено продолжать движение в намеченном направлении только после проезда трамвая."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителю легкового автомобиля продолжить движение в намеченном направлении.</p>","image":"assets/adrive-questions/q100701602.jpg"},{"id":100701701,"themeId":3,"group":1007017,"chapter":7,"chapters":[7],"q":"Разрешается ли водителю легкового автомобиля повернуть направо в показанной обстановке?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, предоставив преимущество пешеходу, переходящему проезжую часть дороги за спиной регулировщика."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля продолжить движение в намеченном направлении, предоставив преимущество пешеходу, переходящему проезжую часть дороги за спиной регулировщика.</p>","image":"assets/adrive-questions/q100701701.jpg"},{"id":100701702,"themeId":3,"group":1007017,"chapter":7,"chapters":[7],"q":"Разрешается ли водителю легкового автомобиля повернуть налево в показанной обстановке?","a":["Нет, не разрешается.","Да, разрешается, уступив дорогу автобусу.","Разрешается, уступив дорогу автобусу и предоставив преимущество пешеходам, переходящим проезжую часть дороги за спиной регулировщика."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителю легкового автомобиля продолжить движение в намеченном направлении.</p>","image":"assets/adrive-questions/q100701702.jpg"},{"id":100701801,"themeId":3,"group":1007018,"chapter":7,"chapters":[7],"q":"Разрешается ли водителю легкового автомобиля повернуть направо в показанной обстановке?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, предоставив преимущество пешеходам, переходящим проезжую часть дороги за спиной регулировщика."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает водителю легкового автомобиля повернуть направо, предоставив преимущество пешеходам, переходящим проезжую часть дороги за спиной регулировщика.</p>","image":"assets/adrive-questions/q100701801.jpg"},{"id":100701802,"themeId":3,"group":1007018,"chapter":7,"chapters":[7],"q":"Разрешается ли водителю легкового автомобиля повернуть налево в показанной обстановке?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, предоставив преимущество пешеходам, переходящим проезжую часть дороги за спиной регулировщика."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика запрещает водителю легкового автомобиля повернуть налево.</p>","image":"assets/adrive-questions/q100701802.jpg"},{"id":100701901,"themeId":3,"group":1007019,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам (за исключением трамваев) поворот направо?","a":["Только «А».","Только «Б».","«А» и «Б».","«Б» и «В».","«А», «Б» и «В»."],"c":4,"e":"<p>Все изображённые на рисунке сигналы регулировщика не запрещают транспортным средствам (за исключением трамваев) поворот направо.</p>","image":"assets/adrive-questions/q100701901.jpg"},{"id":100701902,"themeId":3,"group":1007019,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам (за исключением трамваев) поворот направо?","a":["Только «Б».","Только «В».","«А» и «В».","«Б» и «В».","«А», «Б» и «В»."],"c":1,"e":"<p>Сигнал регулировщика, обозначенный буквой В, не запрещает транспортным средствам (за исключением трамваев) поворот направо.</p>","image":"assets/adrive-questions/q100701902.jpg"},{"id":100702001,"themeId":3,"group":1007020,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам (за исключением трамваев) поворот налево и разворот?","a":["Только «А».","Только «Б».","«А» и «Б».","«Б» и «В».","«А», «Б» и «В»."],"c":1,"e":"<p>Сигнал регулировщика, обозначенный буквой «Б», не запрещает транспортным средствам (за исключением трамваев) поворот налево и разворот.</p>","image":"assets/adrive-questions/q100702001.jpg"},{"id":100702002,"themeId":3,"group":1007020,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам (за исключением трамваев) поворот налево и разворот?","a":["Только «Б».","Только «В».","«А» и «В».","«Б» и «В».","«А», «Б» и «В»."],"c":1,"e":"<p>Сигнал регулировщика, обозначенный буквой В, не запрещает транспортным средствам (за исключением трамваев) поворот налево и разворот.</p>","image":"assets/adrive-questions/q100702002.jpg"},{"id":100702101,"themeId":3,"group":1007021,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам (за исключением трамваев) движение прямо?","a":["Только «А».","Только «Б».","«А» и «Б».","«Б» и «В».","«А», «Б» и «В»."],"c":2,"e":"<p>Сигналы регулировщика, обозначенные буквами «А» и «Б», не запрещают транспортным средствам (за исключением трамваев) движение прямо.</p>","image":"assets/adrive-questions/q100702101.jpg"},{"id":100702102,"themeId":3,"group":1007021,"chapter":7,"chapters":[7],"q":"Какие из показанных сигналов регулировщика, учитывая его положение, не запрещают транспортным средствам движение прямо?","a":["Только «Б».","Только «В».","«А» и «В».","«Б» и «В».","«А», «Б» и «В»."],"c":0,"e":"<p>Сигнал регулировщика, обозначенный буквой «Б», не запрещает транспортным средствам движение прямо.</p>","image":"assets/adrive-questions/q100702102.jpg"},{"id":100702301,"themeId":3,"group":1007023,"chapter":7,"chapters":[7],"q":"Какими согласно Правилам дорожного движения в зависимости от назначения могут быть сигналы светофоров?","a":["Т-образные.","Х-образные.","Y-образные."],"c":1,"e":"<p>Согласно Правилам дорожного движения, сигналы светофоров в зависимости от назначения могут быть Х-образные (применяются в виде запрещающего сигнала на реверсивных светофорах).</p>","image":null},{"id":100702302,"themeId":3,"group":1007023,"chapter":7,"chapters":[7],"q":"Какими согласно Правилам дорожного движения в зависимости от назначения не могут быть сигналы светофоров?","a":["В виде силуэта трамвая.","В виде силуэта всадника.","В виде силуэта пешехода.","В виде силуэта велосипеда."],"c":1,"e":"<p>Согласно Правилам дорожного движения, сигналы светофоров в зависимости от назначения могут быть выполнены в виде силуэта трамвая, пешехода или велосипеда.</p>","image":null},{"id":100702401,"themeId":3,"group":1007024,"chapter":7,"chapters":[7],"q":"Для чего применяется показанный на рисунке светофор?","a":["Для регулирования движения в определённых направлениях.","Для регулирования движения трамваев и других маршрутных транспортных средств.","Для регулирования движения транспортных средств через железнодорожные переезды.","Для регулирования движения на территориях организаций и в местах сужения проезжей части дороги.","Для регулирования движения транспортных средств по полосам проезжей части дороги, по которым направление движения может меняться на противоположное."],"c":4,"e":"<p>Показанный на рисунке светофор применяется для регулирования движения транспортных средств по полосам проезжей части дороги, по которым направление движения может меняться на противоположное (реверсивный светофор).</p>","image":"assets/adrive-questions/q100702401.jpg"},{"id":100702402,"themeId":3,"group":1007024,"chapter":7,"chapters":[7],"q":"Для чего применяется светофор с Х-образным красным сигналом?","a":["Для регулирования движения трамваев и других маршрутных транспортных средств.","Для регулирования движения транспортных средств через железнодорожные переезды.","Для регулирования движения на территориях организаций и в местах сужения проезжей части дороги.","Для регулирования движения транспортных средств по полосам проезжей части дороги, по которым направление движения может меняться на противоположное."],"c":3,"e":"<p>Показанный на рисунке светофор применяется для регулирования движения транспортных средств по полосам проезжей части дороги, по которым направление движения может меняться на противоположное (реверсивный светофор).</p>","image":"assets/adrive-questions/q100702402.jpg"},{"id":100702501,"themeId":3,"group":1007025,"chapter":7,"chapters":[7],"q":"Как должен поступить водитель, если над полосой движения, по которой он движется, расположен показанный на рисунке светофор?","a":["Продолжить движение только прямо.","Продолжить движение только направо.","Остановиться и продолжить движение только направо при включении разрешающего сигнала."],"c":2,"e":"<p>В показанной ситуации светофор действует только на ту полосу, над которой он установлен. Сигналы светофора с изображением контурных стрелок или выполненные в виде стрелок при включении разрешающего сигнала разрешают движение только по направлениям, указываемым стрелками.</p>","image":"assets/adrive-questions/q100702501.jpg"},{"id":100702502,"themeId":3,"group":1007025,"chapter":7,"chapters":[7],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, проехав перекрёсток так, как показано на рисунке?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>В показанной ситуации светофор действует только на ту полосу, над которой он установлен. Сигналы светофора выполнены в виде стрелок, поэтому движение осуществляется только по направлениям, указываемым стрелками.</p>","image":"assets/adrive-questions/q100702502.jpg"},{"id":100702552,"themeId":3,"group":1007025,"chapter":7,"chapters":[7],"q":"Каким транспортным средствам разрешено проехать перекрёсток прямо в показанной ситуации?","a":["Только грузовому автомобилю.","Грузовому автомобилю и автобусу.","Разрешено всем автомобилям."],"c":1,"e":"<p>Согласно требованию дорожного знака «5.8.1 Направления движения по полосам» с левой полосы движение прямо запрещено. При этом включённые на светофоре сигналы разрешают движение в тех же направлениях, что и указаны на дорожном знаке.</p> <p>Поэтому в показанной ситуации прямо на перекрёстке могут двигаться автобус и грузовой автомобиль.</p>","image":"assets/adrive-questions/q100702552.jpg"},{"id":100702601,"themeId":3,"group":1007026,"chapter":7,"chapters":[7],"q":"Разрешается ли Вам в показанной ситуации повернуть направо?","a":["Нет, не разрешается.","Разрешается, предоставив преимущество пешеходу."],"c":1,"e":"<p>В показанной ситуации разрешается повернуть направо, предоставив преимущество пешеходу.</p>","image":"assets/adrive-questions/q100702601.jpg"},{"id":100702602,"themeId":3,"group":1007026,"chapter":7,"chapters":[7],"q":"Разрешается ли Вам в показанной ситуации повернуть налево?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только при условии, что Вы уступите дорогу транспортным средствам, движущимся с других направлений."],"c":0,"e":"<p>В показанной ситуации разрешается повернуть налево. При этом, при движении в направлении стрелки, включённой в дополнительной секции одновременно с зелёным сигналом светофора, Вы имеете преимущество перед транспортными средствами, движущимися с других направлений.</p>","image":"assets/adrive-questions/q100702602.jpg"},{"id":100702701,"themeId":3,"group":1007027,"chapter":7,"chapters":[7],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля при таком сигнале светофора в показанной ситуации?","a":["Только направо.","Прямо и направо.","Движение в показанной ситуации запрещено."],"c":0,"e":"<p>В показанной ситуации водителю синего легкового автомобиля при таких сигналах светофора разрешено продолжить движение только направо.</p>","image":"assets/adrive-questions/q100702701.jpg"},{"id":100702702,"themeId":3,"group":1007027,"chapter":7,"chapters":[7],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля при таком сигнале светофора в показанной ситуации?","a":["Только направо.","Прямо и направо.","Движение в показанной ситуации запрещено."],"c":1,"e":"<p>В показанной ситуации водителю синего легкового автомобиля при таких сигналах светофора разрешено продолжить движение прямо и направо.</p>","image":"assets/adrive-questions/q100702702.jpg"},{"id":100702801,"themeId":3,"group":1007028,"chapter":7,"chapters":[7],"q":"Какие из легковых автомобилей могут продолжить движение через перекрёсток в показанной ситуации при таком сигнале светофора?","a":["Только красный автомобиль.","Красный и синий автомобили.","Жёлтый и красный автомобили.","Все легковые автомобили."],"c":3,"e":"<p>В показанной ситуации при таких сигналах светофора все легковые автомобили могут продолжить движение через перекрёсток (прямо и направо).</p>","image":"assets/adrive-questions/q100702801.jpg"},{"id":100702802,"themeId":3,"group":1007028,"chapter":7,"chapters":[7],"q":"Какие из легковых автомобилей могут продолжить движение через перекрёсток в показанной ситуации при таком сигнале светофора?","a":["Только красный автомобиль.","Синий и красный автомобили.","Красный и жёлтый автомобили.","Все легковые автомобили."],"c":3,"e":"<p>В показанной ситуации при таких сигналах светофора все легковые автомобили могут продолжить движение через перекрёсток.</p>","image":"assets/adrive-questions/q100702802.jpg"},{"id":100702901,"themeId":3,"group":1007029,"chapter":7,"chapters":[7],"q":"В каком направлении разрешено Вам продолжить движение в показанной ситуации?","a":["Только направо.","Прямо и направо.","В показанной ситуации необходимо остановиться."],"c":2,"e":"<p>Красный сигнал светофора запрещает продолжить движение.</p>","image":"assets/adrive-questions/q100702901.jpg"},{"id":100702902,"themeId":3,"group":1007029,"chapter":7,"chapters":[7],"q":"В каком направлении разрешено Вам продолжить движение в показанной ситуации?","a":["Только направо.","Прямо и направо.","В показанной ситуации необходимо остановиться."],"c":2,"e":"<p>Красный сигнал светофора запрещает продолжить движение.</p>","image":"assets/adrive-questions/q100702902.jpg"},{"id":100703001,"themeId":3,"group":1007030,"chapter":7,"chapters":[7],"q":"Какой из перечисленных круглых сигналов светофора является разрешающим?","a":["Жёлтый сигнал.","Жёлтый мигающий сигнал.","Красный мигающий сигнал.","Сочетание красного и жёлтого сигналов."],"c":1,"e":"<p>Согласно Правилам дорожного движения, жёлтый мигающий сигнал круглых светофоров является разрешающим.</p>","image":null},{"id":100703002,"themeId":3,"group":1007030,"chapter":7,"chapters":[7],"q":"Какой из перечисленных круглых сигналов светофора является запрещающим для транспортных средств?","a":["Жёлтый сигнал.","Жёлтый мигающий сигнал.","Зелёный мигающий сигнал."],"c":0,"e":"<p>Согласно Правилам дорожного движения, жёлтый сигнал круглых светофоров является запрещающим.</p>","image":null},{"id":100703101,"themeId":3,"group":1007031,"chapter":7,"chapters":[7],"q":"Какие из легковых автомобилей могут продолжить движение через перекрёсток в показанной ситуации при таком сигнале светофора?","a":["Только красный автомобиль.","Красный и синий автомобили.","Все легковые автомобили."],"c":2,"e":"<p>В показанной ситуации разрешающий сигнал светофора не запрещает продолжить движение через перекрёсток всем легковым автомобилям.</p>","image":"assets/adrive-questions/q100703101.jpg"},{"id":100703102,"themeId":3,"group":1007031,"chapter":7,"chapters":[7],"q":"Что означает сочетание красного и жёлтого сигналов светофора?","a":["Разрешает движение и информирует о неисправности светофора.","Разрешает движение и информирует о предстоящем включении зелёного сигнала.","Запрещает движение и информирует о предстоящем включении зелёного сигнала.","Запрещает движение и информирует о предстоящем включении жёлтого мигающего сигнала."],"c":2,"e":"<p>Сочетание красного и жёлтого сигналов светофора запрещает движение и информирует о предстоящем включении зелёного сигнала.</p>","image":"assets/adrive-questions/q100703102.jpg"},{"id":100703201,"themeId":3,"group":1007032,"chapter":7,"chapters":[7],"q":"Разрешается ли въехать на перекрёсток, если зелёный сигнал на светофоре начал мигать?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только водителям, которые не могут остановиться в положенном месте, не прибегая к экстренному торможению."],"c":0,"e":"<p>Согласно Правилам дорожного движения, зелёный мигающий сигнал круглых светофоров является разрешающим для водителей транспортных средств.</p>","image":null},{"id":100703202,"themeId":3,"group":1007032,"chapter":7,"chapters":[7],"q":"Разрешается ли въехать на перекрёсток, если на светофоре включился жёлтый сигнал?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только водителям, которые не могут остановиться в положенном месте, не прибегая к экстренному торможению."],"c":2,"e":"<p>Согласно Правилам дорожного движения, при включении жёлтого сигнала светофора водителям, которые не могут остановиться в положенном месте, не прибегая к экстренному торможению, разрешено продолжить движение через перекрёсток.</p>","image":null},{"id":100703462,"themeId":3,"group":1007034,"chapter":7,"chapters":[7],"q":"Как должен поступить водитель легкового автомобиля, поворачивая направо в показанной ситуации?","a":["Выполнить поворот и продолжить движение, не останавливаясь перед линией горизонтальной дорожной разметки 1.12 «стоп-линия» у светофора с включённым запрещающим сигналом.","Остановиться перед линией горизонтальной дорожной разметки 1.12 «стоп-линия» у светофора с включённым запрещающим сигналом и, дождавшись разрешающего сигнала светофора, продолжить движение."],"c":1,"e":"<p>После выполнения поворота водитель должен <strong>остановиться перед стоп-линией</strong> у светофора с запрещающим сигналом. Возобновить движение разрешено только после включения разрешающего сигнала светофора.</p>","image":"assets/adrive-questions/q100703462.jpg"},{"id":100704601,"themeId":3,"group":1007046,"chapter":7,"chapters":[7],"q":"Разрешается ли пешеходу начать переход проезжей части дороги в показанной ситуации, если на пешеходном светофоре включился мигающий зелёный сигнал?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, но только до островка безопасности, на котором пешеход обязан остановиться."],"c":1,"e":"<p>В показанной ситуации на пешеходном светофоре включился мигающий зелёный сигнал светофора, который запрещает пешеходу выход на проезжую часть дороги.</p>","image":"assets/adrive-questions/q100704601.jpg"},{"id":100704602,"themeId":3,"group":1007046,"chapter":7,"chapters":[7],"q":"Как должен поступить пешеход, если при переходе проезжей части дороги на пешеходном светофоре начал мигать зелёный сигнал?","a":["Закончить переход проезжих частей дороги.","Дойти до островка безопасности и остановиться на нём.","Дойти до линии, разделяющей попутные потоки транспортных средств, и остановиться."],"c":1,"e":"<p>В показанной ситуации при переходе проезжей части дороги на пешеходном светофоре начал мигать зелёный сигнал, поэтому пешеход должен дойти до островка безопасности и остановиться на нём.</p>","image":"assets/adrive-questions/q100704602.jpg"},{"id":100704603,"themeId":3,"group":1007046,"chapter":7,"chapters":[7],"q":"Как должен поступить пешеход, если при переходе проезжей части дороги на пешеходном светофоре начал мигать зелёный сигнал?","a":["Закончить переход проезжей части дороги.","Дойти до линии, разделяющей попутные потоки транспортных средств, и остановиться.","Дойти до линии, разделяющей встречные потоки транспортных средств, и остановиться."],"c":0,"e":"<p>В показанной ситуации при переходе проезжей части дороги на пешеходном светофоре начал мигать зелёный сигнал, поэтому пешеход должен закончить переход проезжей части дороги. Запрещается останавливаться при переходе проезжей части дороги на линиях, разделяющих встречные или попутные потоки транспортных средств.</p>","image":"assets/adrive-questions/q100704603.jpg"},{"id":100704701,"themeId":3,"group":1007047,"chapter":7,"chapters":[7],"q":"Разрешается ли пешеходу начать переход проезжей части дороги в показанной ситуации, если на пешеходном светофоре включился красный сигнал, а транспортные средства ещё не начали движение?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, но только до островка безопасности, на котором пешеход обязан остановиться."],"c":1,"e":"<p>В показанной ситуации на пешеходном светофоре включился красный сигнал светофора, который запрещает движение пешеходу.</p>","image":"assets/adrive-questions/q100704701.jpg"},{"id":100704702,"themeId":3,"group":1007047,"chapter":7,"chapters":[7],"q":"Как должен поступить пешеход, если при переходе проезжей части дороги на пешеходном светофоре включился красный сигнал?","a":["Закончить переход проезжих частей дороги.","Дойти до островка безопасности и остановиться на нём.","Дойти до линии, разделяющей попутные потоки транспортных средств, и остановиться."],"c":1,"e":"<p>В показанной ситуации при переходе проезжей части дороги на пешеходном светофоре включился красный сигнал, поэтому пешеход должен дойти до островка безопасности и остановиться на нём.</p>","image":"assets/adrive-questions/q100704702.jpg"},{"id":100704703,"themeId":3,"group":1007047,"chapter":7,"chapters":[7],"q":"Как должен поступить пешеход, если при переходе проезжей части дороги на пешеходном светофоре включился красный сигнал?","a":["Закончить переход проезжей части дороги.","Дойти до линии, разделяющей попутные потоки транспортных средств, и остановиться.","Дойти до линии, разделяющей встречные потоки транспортных средств, и остановиться."],"c":0,"e":"<p>В показанной ситуации при переходе проезжей части дороги на пешеходном светофоре включился красный сигнал, поэтому пешеход должен закончить переход проезжей части дороги. Запрещается останавливаться при переходе проезжей части дороги на линиях, разделяющих встречные или попутные потоки транспортных средств.</p>","image":"assets/adrive-questions/q100704703.jpg"},{"id":100704801,"themeId":3,"group":1007048,"chapter":7,"chapters":[7],"q":"С какой целью разрешающий сигнал пешеходного светофора может быть дополнен по периметру кольцом жёлтого цвета?","a":["Для дополнительного информирования пешеходов о возможности пересечения проезжей части дороги.","Для информирования пешеходов об истечении разрешённого времени для перехода проезжей части дороги.","Для информирования пешеходов о том, что через пешеходный переход могут двигаться транспортные средства, выполняющие на перекрёстке правый и (или) левый поворот."],"c":2,"e":"<p>Разрешающий сигнал пешеходного светофора может быть дополнен по периметру кольцом жёлтого цвета для информирования пешеходов о том, что через пешеходный переход могут двигаться транспортные средства, выполняющие на перекрёстке правый и (или) левый поворот.</p>","image":"assets/adrive-questions/q100704801.jpg"},{"id":100704802,"themeId":3,"group":1007048,"chapter":7,"chapters":[7],"q":"Кольцом какого цвета может быть дополнен по периметру разрешающий сигнал пешеходного светофора для информирования пешеходов о том, что через пешеходный переход могут двигаться транспортные средства, выполняющие на перекрёстке правый и (или) левый поворот?","a":["Жёлтого цвета.","Зелёного цвета.","Красного цвета."],"c":0,"e":"<p>Согласно Правилам дорожного движения, кольцом жёлтого цвета может быть дополнен по периметру разрешающий сигнал пешеходного светофора для информирования пешеходов о том, что через пешеходный переход могут двигаться транспортные средства, выполняющие на перекрёстке правый и (или) левый поворот.</p>","image":null},{"id":100704901,"themeId":3,"group":1007049,"chapter":7,"chapters":[7],"q":"Что означает показанный на рисунке сигнал светофора?","a":["Движение разрешено только по крайней правой полосе движения.","Движение разрешено по полосе движения, над которой он установлен.","Движение запрещено, необходимо остановиться в месте, указанном стрелкой."],"c":1,"e":"<p>Показанный на рисунке сигнал реверсивного светофора разрешает движение по полосе, над которой он установлен.</p>","image":"assets/adrive-questions/q100704901.jpg"},{"id":100704902,"themeId":3,"group":1007049,"chapter":7,"chapters":[7],"q":"Что означает показанный на рисунке сигнал светофора?","a":["Приближение к повороту дороги направо.","Приближение к сужению проезжей части дороги.","Движение разрешено только по крайней правой полосе движения.","Предстоит смена сигналов светофора, необходимо перестроиться на полосу движения справа."],"c":3,"e":"<p>Показанный на рисунке сигнал реверсивного светофора означает, что предстоит смена сигнала светофора на красный, необходимо перестроиться на полосу движения справа.</p>","image":"assets/adrive-questions/q100704902.jpg"},{"id":100704903,"themeId":3,"group":1007049,"chapter":7,"chapters":[7],"q":"Что означает показанный на рисунке сигнал светофора?","a":["Светофор неисправен или выключен.","Движение запрещено по крайней левой полосе движения.","Движение запрещено по полосе движения, над которой он установлен."],"c":2,"e":"<p>Показанный на рисунке сигнал реверсивного светофора означает, что движение запрещено по полосе движения, над которой он установлен.</p>","image":"assets/adrive-questions/q100704903.jpg"},{"id":100705001,"themeId":3,"group":1007050,"chapter":7,"chapters":[7],"q":"Кто из водителей в показанной ситуации совершает манёвр без нарушения Правил дорожного движения?","a":["Водитель синего легкового автомобиля, совершающий разворот.","Водитель жёлтого легкового автомобиля, совершающий перестроение.","Оба водителя не нарушают Правила дорожного движения.","Оба водителя нарушают Правила дорожного движения."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.9 и горит разрешающий сигнал реверсивного светофора.</p> <p>При включённых зелёных сигналах реверсивных светофоров линию 1.9 разрешается пересекать с любой стороны, если она разделяет полосы, по которым движение разрешено в одном направлении.</p> <p>Поэтому водитель жёлтого легкового автомобиля, совершающий перестроение, не нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q100705001.jpg"},{"id":100705002,"themeId":3,"group":1007050,"chapter":7,"chapters":[7],"q":"Кто из водителей в показанной ситуации совершает манёвр без нарушения Правил дорожного движения?","a":["Водитель синего легкового автомобиля, совершающий перестроение.","Водитель жёлтого легкового автомобиля, совершающий перестроение.","Оба водителя не нарушают Правила дорожного движения.","Оба водителя нарушают Правила дорожного движения."],"c":1,"e":"<p>В показанной ситуации водитель жёлтого легкового автомобиля, совершающий перестроение, совершает манёвр без нарушения Правил дорожного движения.</p> <p>Водителю синего легкового автомобиля запрещено перестраиваться на полосу с реверсивным движением при включённом жёлтом сигнале светофора.</p>","image":"assets/adrive-questions/q100705002.jpg"},{"id":100705101,"themeId":3,"group":1007051,"chapter":7,"chapters":[7],"q":"Разрешается ли выполнить опережение по второй полосе движения водителю жёлтого автомобиля в показанной ситуации (реверсивный светофор выключен)?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.9 и реверсивный светофор выключен. При выключенных реверсивных светофорах линию разметки 1.9, находящуюся слева, пересекать запрещается. Поэтому водителю жёлтого автомобиля выполнить опережение по второй полосе движения запрещается.</p>","image":"assets/adrive-questions/q100705101.jpg"},{"id":100705102,"themeId":3,"group":1007051,"chapter":7,"chapters":[7],"q":"Разрешается ли выполнить обгон водителю жёлтого автомобиля в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.9 и горит запрещающий сигнал реверсивного светофора. При запрещающем сигнале реверсивных светофорах линию разметки 1.9, находящуюся слева, пересекать запрещается. Поэтому водителю жёлтого автомобиля выполнить обгон запрещается.</p>","image":"assets/adrive-questions/q100705102.jpg"},{"id":100705201,"themeId":3,"group":1007052,"chapter":7,"chapters":[7],"q":"Какой из показанных светофоров применяется для регулирования движения через железнодорожные переезды?","a":["Светофор 1.","Светофор 2.","Светофор 3.","Светофор 4.","Светофор 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён светофор, который применяется для регулирования движения через железнодорожные переезды.</p>","image":"assets/adrive-questions/q100705201.jpg"},{"id":100705202,"themeId":3,"group":1007052,"chapter":7,"chapters":[7],"q":"Какой из показанных светофоров применяется для регулирования движения через железнодорожные переезды?","a":["Светофор 1.","Светофор 2.","Светофор 3.","Светофор 4.","Светофор 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён светофор, который применяется для регулирования движения через железнодорожные переезды.</p>","image":"assets/adrive-questions/q100705202.jpg"},{"id":100705301,"themeId":3,"group":1007053,"chapter":7,"chapters":[7],"q":"О чём информирует мигающий бело-лунный сигнал светофора, применяемого для регулирования движения через железнодорожные переезды?","a":["О том, что сигнализация исправна, и не запрещает движение.","О том, что сигнализация неисправна, и запрещает движение.","О том, что сигнализация неисправна, и не запрещает движение.","О том, что к переезду приближается железнодорожное транспортное средство."],"c":0,"e":"<p>Согласно Правилам дорожного движения, мигающий бело-лунный сигнал светофора, применяемого для регулирования движения через железнодорожные переезды, дополнительно обозначает железнодорожный переезд, информирует о том, что сигнализация исправна, и не запрещает движение транспортных средств, участников дорожного движения.</p>","image":null},{"id":100705302,"themeId":3,"group":1007053,"chapter":7,"chapters":[7],"q":"О чём информирует звуковой сигнал, применяемый со светофором, предназначенным для регулирования движения через железнодорожные переезды?","a":["Дополнительно предупреждает о закрытии шлагбаума.","Дополнительно информирует о запрещении движения через железнодорожный переезд.","Дополнительно предупреждает о возможной опасности при движении через железнодорожный переезд."],"c":1,"e":"<p>Согласно Правилам дорожного движения, звуковой сигнал, применяемый со светофором, предназначенным для регулирования движения через железнодорожные переезды, дополнительно информирует о запрещении движения через железнодорожный переезд.</p>","image":null},{"id":113100101,"themeId":3,"group":1131001,"chapter":86,"chapters":[86],"q":"Обязаны ли Вы в показанной ситуации, поворачивая направо, предоставить преимущество пешеходу?","a":["Да, обязаны.","Нет, не обязаны."],"c":0,"e":"<p>В показанной ситуации, поворачивая направо, Вы обязаны предоставить преимущество пешеходу, переходящему (пересекающему) проезжую часть дороги, на которую поворачиваете.</p>","image":"assets/adrive-questions/q113100101.jpg"},{"id":113100102,"themeId":3,"group":1131001,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу (предоставить преимущество)?","a":["Пешеход.","Водитель автомобиля."],"c":1,"e":"<p>В показанной ситуации, поворачивая направо, водитель обязан предоставить преимущество пешеходу, пересекающему проезжую часть по пешеходному переходу.</p>","image":"assets/adrive-questions/q113100102.jpg"},{"id":113100103,"themeId":3,"group":1131001,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу (предоставить преимущество)?","a":["Пешеход.","Водитель автомобиля."],"c":1,"e":"<p>В показанной ситуации, поворачивая направо, водитель обязан предоставить преимущество пешеходу, пересекающему проезжую часть по пешеходному переходу.</p>","image":"assets/adrive-questions/q113100103.jpg"},{"id":113100201,"themeId":3,"group":1131002,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации пользуется преимуществом в движении?","a":["Велосипедист.","Водитель автомобиля."],"c":0,"e":"<p>В показанной ситуации, поворачивая направо, водитель обязан уступить дорогу велосипедисту, движущемуся по велосипедной дорожке.</p>","image":"assets/adrive-questions/q113100201.jpg"},{"id":113100202,"themeId":3,"group":1131002,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Велосипедист.","Водитель автомобиля."],"c":1,"e":"<p>В показанной ситуации, поворачивая направо, водитель обязан уступить дорогу велосипедисту, движущемуся по велосипедной дорожке.</p>","image":"assets/adrive-questions/q113100202.jpg"},{"id":113100301,"themeId":3,"group":1131003,"chapter":86,"chapters":[86],"q":"Разрешается ли Вам, управляя легковым автомобилем, выехать на перекрёсток в показанной ситуации, если впереди образовался затор?","a":["Запрещается.","Разрешается, если это не вынудит Вас остановиться на перекрёстке и (или) пешеходном переходе."],"c":1,"e":"<p>В показанной ситуации впереди образовался затор на незначительном удалении от перекрёстка, поэтому водителю разрешается выехать на перекрёсток, если это не вынудит его остановиться на перекрёстке и (или) пешеходном переходе.</p>","image":"assets/adrive-questions/q113100301.jpg"},{"id":113100302,"themeId":3,"group":1131003,"chapter":86,"chapters":[86],"q":"Разрешается ли Вам, управляя легковым автомобилем, выехать на перекрёсток в показанной ситуации, если впереди образовался затор?","a":["Разрешается.","Разрешается только для поворота направо.","Разрешается только для поворота направо, налево или разворота.","Запрещается."],"c":2,"e":"<p>В показанной ситуации впереди образовался затор, поэтому водителю разрешается выехать на перекрёсток только для поворота направо, налево или разворота.</p>","image":"assets/adrive-questions/q113100302.jpg"},{"id":113100402,"themeId":3,"group":1131004,"chapter":86,"chapters":[86],"q":"Разрешается ли водителю зелёного легкового автомобиля выехать на перекрёсток для дальнейшего движения прямо при включении зелёного сигнала светофора?","a":["Разрешается.","Запрещается, если образовавшийся на перекрёстке затор вынудит его остановиться."],"c":1,"e":"<p>В показанной ситуации впереди образовался затор, поэтому водителю зелёного легкового автомобиля запрещается выехать на перекрёсток для дальнейшего движения прямо при включении зелёного сигнала светофора.</p>","image":"assets/adrive-questions/q113100402.jpg"},{"id":113100641,"themeId":3,"group":1131006,"chapter":86,"chapters":[86],"q":"Разрешено ли водителю синего легкового автомобиля продолжить движение через пешеходный переход в показанной ситуации?","a":["Нет, не разрешено, так как в момент пересечения траектории движения пешехода расстояние до пешехода составит менее двух полос движения.","Разрешено, так как в данный момент расстояние до пешехода составляет две полосы движения."],"c":0,"e":"<p>При повороте направо водитель обязан предоставить преимущество пешеходам, переходящим проезжую часть дороги, на которую он поворачивает.</p> <p>Преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства.</p> <p>Очевидно, что при осуществлении поворота направо, в момент пересечения траектории движения пешехода расстояние до него составит менее двух полос движения, и пешеход может изменить скорость перехода проезжей части дороги.</p>","image":"assets/adrive-questions/q113100641.jpg"},{"id":113100642,"themeId":3,"group":1131006,"chapter":86,"chapters":[86],"q":"Нарушил ли Правила дорожного движения водитель грузового автомобиля, выполняя поворот налево на перекрёстке в показанной ситуации?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>При повороте налево водитель обязан предоставить преимущество пешеходам, переходящим проезжую часть дороги, на которую он поворачивает. При этом преимущество пешеходу считается предоставленным, если расстояние между транспортным средством и приближающимся пешеходом (в момент пересечения транспортным средством траектории движения пешехода) составило не менее двух полос движения транспортного средства (в том числе одну полосу и трамвайные пути попутного направления).</p> <p>Трамвайный путь попутного направления по ширине равен трамвайному пути встречного направления. Учитывая, что в термине приведён не исключительный список («в том числе...»), два трамвайных пути приравнены к двум полосам движения транспортного средства.</p> <p>Поэтому в показанной ситуации водитель предоставил преимущество пешеходу.</p>","image":"assets/adrive-questions/q113100642.jpg"},{"id":113200101,"themeId":3,"group":1132001,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель зелёного легкового автомобиля?","a":["Уступить дорогу трамваю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал светофора разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте налево необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200101.jpg"},{"id":113200102,"themeId":3,"group":1132001,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель красного легкового автомобиля?","a":["Уступить дорогу трамваю.","Остановиться и подождать другого жеста регулировщика.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200102.jpg"},{"id":113200201,"themeId":3,"group":1132002,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля, разворачиваясь на перекрёстке?","a":["Уступить дорогу трамваю.","Остановиться и подождать другого жеста регулировщика.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при выполнении разворота необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200201.jpg"},{"id":113200202,"themeId":3,"group":1132002,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля, если ему необходимо проехать прямо?","a":["Уступить дорогу трамваю.","Остановиться и подождать другого жеста регулировщика.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при движении прямо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200202.jpg"},{"id":113200301,"themeId":3,"group":1132003,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля, если ему необходимо повернуть направо?","a":["Уступить дорогу трамваю.","Остановиться и подождать другого жеста регулировщика.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200301.jpg"},{"id":113200302,"themeId":3,"group":1132003,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля, если ему необходимо повернуть направо?","a":["Уступить дорогу трамваю.","Остановиться и подождать другого жеста регулировщика.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200302.jpg"},{"id":113200401,"themeId":3,"group":1132004,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель красного легкового автомобиля, если ему необходимо повернуть налево?","a":["Уступить дорогу только трамваю.","Уступить дорогу только троллейбусу.","Уступить дорогу трамваю и троллейбусу.","Повернуть налево, пользуясь преимуществом."],"c":0,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте налево необходимо уступить дорогу трамваю. Движение троллейбусу запрещено.</p>","image":"assets/adrive-questions/q113200401.jpg"},{"id":113200402,"themeId":3,"group":1132004,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель белого легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Уступить дорогу трамваю.","Проехать перекрёсток первым, пользуясь преимуществом."],"c":0,"e":"<p>В показанной ситуации зелёный сигнал светофора разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при движении прямо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113200402.jpg"},{"id":113200501,"themeId":3,"group":1132005,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель белого легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Уступить дорогу только трамваю.","Уступить дорогу трамваю и автобусу.","Проехать перекрёсток первым, пользуясь преимуществом."],"c":0,"e":"<p>В показанной ситуации зелёный сигнал светофора разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при движении прямо необходимо уступить дорогу трамваю. Водитель автобуса, поворачивая налево, обязан уступить дорогу водителю легкового автомобиля.</p>","image":"assets/adrive-questions/q113200501.jpg"},{"id":113200502,"themeId":3,"group":1132005,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля, если ему необходимо повернуть направо?","a":["Уступить дорогу только трамваю, находящемуся слева.","Уступить дорогу только трамваю, находящемуся справа.","Уступить дорогу обоим трамваям."],"c":2,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваям, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу обоим трамваям.</p>","image":"assets/adrive-questions/q113200502.jpg"},{"id":113200601,"themeId":3,"group":1132006,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель белого легкового автомобиля?","a":["Уступить дорогу синему легковому автомобилю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":1,"e":"<p>В показанной ситуации водитель синего легкового автомобиля движется в направлении стрелки, включённой в дополнительной секции одновременно с красным сигналом светофора, поэтому должен уступить дорогу водителю белого автомобиля.</p>","image":"assets/adrive-questions/q113200601.jpg"},{"id":113200602,"themeId":3,"group":1132006,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель синего легкового автомобиля?","a":["Уступить дорогу только трамваю, находящемуся слева.","Уступить дорогу только трамваю, находящемуся справа.","Уступить дорогу обоим трамваям.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":2,"e":"<p>В показанной ситуации водитель синего легкового автомобиля движется в направлении стрелки, включённой в дополнительной секции одновременно с красным сигналом светофора, поэтому должен уступить дорогу обоим трамваям, движущимся с других направлений.</p>","image":"assets/adrive-questions/q113200602.jpg"},{"id":113200603,"themeId":3,"group":1132006,"chapter":86,"chapters":[86],"q":"Как в показанной ситуации должен поступить водитель белого легкового автомобиля?","a":["Уступить дорогу только трамваю.","Уступить дорогу только автобусу.","Уступить дорогу трамваю и автобусу.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":2,"e":"<p>В показанной ситуации водитель белого легкового автомобиля движется в направлении стрелки, включённой в дополнительной секции одновременно с красным сигналом светофора, поэтому водитель белого легкового автомобиля должен уступить дорогу трамваю и автобусу, движущимся с других направлений.</p>","image":"assets/adrive-questions/q113200603.jpg"},{"id":113200701,"themeId":3,"group":1132007,"chapter":86,"chapters":[86],"q":"Как Вы должны поступить в показанной ситуации, поворачивая налево?","a":["Уступить дорогу автобусу.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации Вы, двигаясь на разрешающий сигнал светофора, при повороте налево должны уступить дорогу автобусу, движущемуся прямо.</p>","image":"assets/adrive-questions/q113200701.jpg"},{"id":113200702,"themeId":3,"group":1132007,"chapter":86,"chapters":[86],"q":"Как Вы, двигаясь прямо на перекрёстке, должны поступить в показанной ситуации?","a":["Уступить дорогу автобусу.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":1,"e":"<p>В показанной ситуации водитель автобуса, двигаясь на разрешающий сигнал светофора, при повороте налево должен уступить дорогу транспортным средствам, движущимся прямо.</p>","image":"assets/adrive-questions/q113200702.jpg"},{"id":113200801,"themeId":3,"group":1132008,"chapter":86,"chapters":[86],"q":"Как Вы должны поступить при движении прямо на перекрёстке в показанной ситуации?","a":["Уступить дорогу встречному трамваю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации, двигаясь на разрешающий сигнал светофора, Вы должны уступить дорогу трамваю, так как в равных условиях трамвай имеет преимущество перед другими транспортными средствами.</p>","image":"assets/adrive-questions/q113200801.jpg"},{"id":113200802,"themeId":3,"group":1132008,"chapter":86,"chapters":[86],"q":"Как поступить водителю легкового автомобиля, если ему необходимо повернуть налево?","a":["Уступить дорогу автобусу.","Пользуясь преимуществом, проехать перекрёсток одновременно с трамваем."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля, двигаясь на разрешающий сигнал светофора, при повороте налево должен уступить дорогу автобусу, движущемуся прямо</p>","image":"assets/adrive-questions/q113200802.jpg"},{"id":113200852,"themeId":3,"group":1132008,"chapter":86,"chapters":[86],"q":"В показанной ситуации при движении на перекрёстке прямо Вы:","a":["Имеете преимущество.","Должны уступить дорогу только трамваю.","Должны уступить дорогу трамваю и грузопассажирскому фургону."],"c":1,"e":"<p>Знаки приоритета не устанавливают очерёдность проезда перекрёстка, когда светофоры работают в обычном режиме.</p> <p>Двигаясь прямо на разрешающий сигнал светофора, Вы обязаны уступить дорогу только трамваю, поскольку в равных условиях он пользуется преимуществом.</p>","image":"assets/adrive-questions/q113200852.jpg"},{"id":113200901,"themeId":3,"group":1132009,"chapter":86,"chapters":[86],"q":"Как поступить водителю белого легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Уступить дорогу только трамваю.","Уступить дорогу трамваю и автобусу.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации все ТС осуществляют движение по разрешающему сигналу светофора, поэтому водитель белого легкового автомобиля при движении прямо должен уступить дорогу только трамваю. Водитель автобуса, поворачивая налево, обязан уступить дорогу обоим транспортным средствам.</p>","image":"assets/adrive-questions/q113200901.jpg"},{"id":113200902,"themeId":3,"group":1132009,"chapter":86,"chapters":[86],"q":"Как Вы должны поступить в показанной ситуации, если Вам необходимо повернуть налево?","a":["Уступить дорогу красному легковому автомобилю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации Вы, двигаясь на разрешающий сигнал светофора, при повороте налево должны уступить дорогу легковому автомобилю, поворачивающему направо.</p>","image":"assets/adrive-questions/q113200902.jpg"},{"id":113201001,"themeId":3,"group":1132010,"chapter":86,"chapters":[86],"q":"Как необходимо поступить водителю красного легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Повернуть направо перед автобусом, движущимся слева.","Повернуть направо после проезда автобуса, движущегося слева.","Оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.","После проезда автобуса выехать на перекрёсток, чтобы скопившиеся за ним транспортные средства имели возможность повернуть направо."],"c":1,"e":"<p>В показанной ситуации при включённой стрелке дополнительной секции светофора водитель красного легкового автомобиля, находясь в крайней правой полосе движения, должен повернуть направо после проезда автобуса, движущегося слева, чтобы не создавать препятствие для движения транспортных средств, поворачивающих направо.</p>","image":"assets/adrive-questions/q113201001.jpg"},{"id":113201002,"themeId":3,"group":1132010,"chapter":86,"chapters":[86],"q":"Как необходимо поступить водителю красного легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Повернуть налево или развернуться.","Оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.","Выехать на перекрёсток, чтобы скопившиеся за ним транспортные средства имели возможность повернуть налево или развернуться."],"c":0,"e":"<p>В показанной ситуации при включённой стрелке дополнительной секции светофора водитель красного легкового автомобиля, находясь в крайней левой полосе движения, должен повернуть налево или развернуться, чтобы не создавать препятствие для движения транспортных средств, разворачивающихся или поворачивающих налево.</p>","image":"assets/adrive-questions/q113201002.jpg"},{"id":113201101,"themeId":3,"group":1132011,"chapter":86,"chapters":[86],"q":"Как поступить водителю красного легкового автомобиля, если ему необходимо повернуть направо?","a":["Уступить дорогу трамваю.","Пользуясь преимуществом, проехать перекрёсток первым."],"c":0,"e":"<p>В показанной ситуации сигналы светофоров разрешают движение одновременно красному легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу трамваю, так как они осуществляют движение с одного направления.</p>","image":"assets/adrive-questions/q113201101.jpg"},{"id":113201141,"themeId":3,"group":1132011,"chapter":86,"chapters":[86],"q":"При повороте налево в показанной ситуации, Вы, управляя легковым автомобилем:","a":["Имеете преимущество.","Должны уступить дорогу автобусу, поворачивающему направо со встречного направления."],"c":0,"e":"<p>При движении в направлении стрелки, включённой в дополнительной секции одновременно с зелёным сигналом светофора, водитель имеет преимущество перед транспортными средствами, движущимися с других направлений.</p>","image":"assets/adrive-questions/q113201141.jpg"},{"id":113201143,"themeId":3,"group":1132011,"chapter":86,"chapters":[86],"q":"Как следует поступить в показанной ситуации, выполняя поворот налево или разворот?","a":["Пользуясь преимуществом, проехать перекрёсток первым.","Уступить дорогу встречным транспортным средствам."],"c":1,"e":"<p>При повороте налево или развороте по зелёному сигналу светофора водитель транспортного средства, за исключением трамвая, обязан уступить дорогу встречным транспортным средствам, движущимся прямо или направо.</p> <p>При этом, обратите внимание, что в показанной ситуации поворот (разворот) осуществляется не в направлении стрелки, включённой в дополнительной секции одновременно с зелёным сигналом светофора.</p>","image":"assets/adrive-questions/q113201143.jpg"},{"id":113201201,"themeId":3,"group":1132012,"chapter":86,"chapters":[86],"q":"Как поступить водителю синего легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Повернуть направо.","Оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.","Выехать на перекрёсток, чтобы скопившиеся за ним транспортные средства имели возможность повернуть направо."],"c":1,"e":"<p>В показанной ситуации синий легковой автомобиль находится не на крайней правой полосе движения, поэтому водителю синего легкового автомобиля для проезда прямо разрешено оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.</p>","image":"assets/adrive-questions/q113201201.jpg"},{"id":113201202,"themeId":3,"group":1132012,"chapter":86,"chapters":[86],"q":"Как поступить водителю синего легкового автомобиля, если ему необходимо проехать перекрёсток прямо?","a":["Повернуть направо.","Оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.","Выехать на перекрёсток, сместившись влево в сторону свободной полосы движения, чтобы скопившиеся за ним транспортные средства имели возможность повернуть направо."],"c":1,"e":"<p>В показанной ситуации перед перекрёстком установлены дорожные знаки 5.8.2 «Направление движения по полосе» , поэтому водителю синего легкового автомобиля для проезда прямо разрешено оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.</p>","image":"assets/adrive-questions/q113201202.jpg"},{"id":113201301,"themeId":3,"group":1132013,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель синего легкового автомобиля, совершающего разворот.","Водитель красного легкового автомобиля, поворачивающего направо."],"c":1,"e":"<p>В показанной ситуации водитель красного легкового автомобиля поворачивает в направлении стрелки, включённой в дополнительной секции одновременно с красным сигналом светофора, поэтому должен уступить дорогу транспортному средству, движущемуся с иного направления.</p>","image":"assets/adrive-questions/q113201301.jpg"},{"id":113201302,"themeId":3,"group":1132013,"chapter":86,"chapters":[86],"q":"Как поступить водителю красного автомобиля, намеревающемуся повернуть направо, если сзади него скопились транспортные средства в ожидании проезда прямо?","a":["Проехать перекрёсток прямо.","Повернуть направо, остановившись перед пешеходным переходом.","Оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора."],"c":2,"e":"<p>В показанной ситуации не включена стрелка в дополнительной секции светофора, поэтому водитель красного легкового автомобиля, который намеревается повернуть направо, должен оставаться в занимаемой полосе движения в ожидании разрешающего сигнала светофора.</p>","image":"assets/adrive-questions/q113201302.jpg"},{"id":113201401,"themeId":3,"group":1132014,"chapter":86,"chapters":[86],"q":"В какой последовательности должны проехать перекрёсток транспортные средства в показанной ситуации?","a":["Трамвай, затем — красный легковой автомобиль и последним — синий легковой автомобиль.","Красный легковой автомобиль, затем — трамвай одновременно с синим легковым автомобилем.","Трамвай одновременно с синим легковым автомобилем, затем — красный легковой автомобиль."],"c":1,"e":"<p>В показанной ситуации стрелка включена в дополнительной секции одновременно с красным сигналом светофора, поэтому первым проехать перекрёсток должен красный легковой автомобиль, затем — трамвай одновременно с синим легковым автомобилем.</p>","image":"assets/adrive-questions/q113201401.jpg"},{"id":113201501,"themeId":3,"group":1132015,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель трамвая.","Водитель синего легкового автомобиля."],"c":1,"e":"<p>В показанной ситуации сигнал светофора разрешает движение одновременно синему легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте налево необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113201501.jpg"},{"id":113201502,"themeId":3,"group":1132015,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель трамвая.","Водитель грузового автомобиля."],"c":1,"e":"<p>В показанной ситуации сигнал светофора разрешает движение одновременно грузовому автомобилю и трамваю, поэтому водителю грузового автомобиля при движении прямо необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113201502.jpg"},{"id":113201601,"themeId":3,"group":1132016,"chapter":86,"chapters":[86],"q":"В показанной ситуации водитель легкового автомобиля при повороте направо:","a":["Имеет преимущество.","Должен уступить дорогу трамваю.","Должен дождаться разрешающего сигнала светофора.","Должен уступить дорогу трамваю и грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте направо необходимо уступить дорогу трамваю. Движение грузовому автомобилю запрещено.</p>","image":"assets/adrive-questions/q113201601.jpg"},{"id":113201602,"themeId":3,"group":1132016,"chapter":86,"chapters":[86],"q":"В показанной ситуации водитель легкового автомобиля при повороте налево:","a":["Имеет преимущество.","Должен уступить дорогу трамваю."],"c":1,"e":"<p>В показанной ситуации сигнал регулировщика разрешает движение одновременно легковому автомобилю и трамваю, поэтому водителю легкового автомобиля при повороте налево необходимо уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113201602.jpg"},{"id":113201701,"themeId":3,"group":1132017,"chapter":86,"chapters":[86],"q":"При проезде показанного на рисунке перекрёстка водитель грузового автомобиля:","a":["Обязан уступить дорогу обоим трамваям.","Обязан уступить дорогу только трамваю попутного направления.","Имеет преимущество перед другими участниками дорожного движения."],"c":0,"e":"<p>В показанной ситуации сигнал светофора разрешает движение одновременно грузовому автомобилю и трамваям, поэтому водителю грузового автомобиля при повороте налево необходимо уступить дорогу обоим трамваям.</p>","image":"assets/adrive-questions/q113201701.jpg"},{"id":113201702,"themeId":3,"group":1132017,"chapter":86,"chapters":[86],"q":"При проезде показанного на рисунке перекрёстка водитель грузового автомобиля:","a":["Обязан предоставить преимущество только пешеходам.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу трамваю и предоставить преимущество пешеходам.","Имеет преимущество перед другими участниками дорожного движения."],"c":2,"e":"<p>В показанной ситуации сигнал светофора разрешает движение одновременно грузовому автомобилю и трамваю, поэтому водителю грузового автомобиля при повороте налево необходимо уступить дорогу трамваю, а также предоставить преимущество пешеходам, переходящим проезжую часть дороги по регулируемому пешеходному переходу.</p>","image":"assets/adrive-questions/q113201702.jpg"},{"id":113201801,"themeId":3,"group":1132018,"chapter":86,"chapters":[86],"q":"Должен ли водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны остановиться перед запрещающим сигналом светофора в показанной ситуации при повороте налево?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>В показанной ситуации перед светофором отсутствует горизонтальная дорожная разметка 1.12 «стоп-линия» и (или) дорожный знак 5.33 «Стоп-линия» , поэтому водитель грузового автомобиля не должен останавливаться перед светофором с запрещающим сигналом.</p>","image":"assets/adrive-questions/q113201801.jpg"},{"id":113201802,"themeId":3,"group":1132018,"chapter":86,"chapters":[86],"q":"Должен ли водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны остановиться перед запрещающим сигналом светофора в показанной ситуации, если ему необходимо развернуться на перекрёстке?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>В показанной ситуации перед светофором отсутствует горизонтальная дорожная разметка 1.12 «стоп-линия» и (или) дорожный знак 5.33 «Стоп-линия» , поэтому водитель грузового автомобиля не должен останавливаться перед светофором с запрещающим сигналом.</p>","image":"assets/adrive-questions/q113201802.jpg"},{"id":113201901,"themeId":3,"group":1132019,"chapter":86,"chapters":[86],"q":"Должен ли водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны остановиться перед запрещающим сигналом светофора в показанной ситуации?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>В показанной ситуации перед светофором с запрещающим сигналом имеется горизонтальная дорожная разметка 1.12 «стоп-линия» и дорожный знак 5.33 «Стоп-линия» , поэтому водитель грузового автомобиля должен остановиться перед стоп-линией.</p>","image":"assets/adrive-questions/q113201901.jpg"},{"id":113201902,"themeId":3,"group":1132019,"chapter":86,"chapters":[86],"q":"Должен ли водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны остановиться перед жёлтым мигающим сигналом светофора в показанной ситуации?","a":["Да, должен.","Нет, не должен."],"c":1,"e":"<p>В показанной ситуации жёлтый мигающий сигнал светофора не запрещает движение, поэтому водителю грузового автомобиля не надо останавливаться.</p>","image":"assets/adrive-questions/q113201902.jpg"},{"id":113202001,"themeId":3,"group":1132020,"chapter":86,"chapters":[86],"q":"Как необходимо поступить, совершая правый поворот, при включении разрешающего сигнала светофора?","a":["Уступить дорогу трактору, завершающему разворот.","Пользуясь преимуществом, проехать в намеченном направлении первым."],"c":0,"e":"<p>В показанной ситуации Вы, совершая правый поворот, при включении разрешающего сигнала светофора должны уступить дорогу трактору, завершающему разворот.</p>","image":"assets/adrive-questions/q113202001.jpg"},{"id":113202002,"themeId":3,"group":1132020,"chapter":86,"chapters":[86],"q":"Должен ли водитель синего легкового автомобиля при включении разрешающего сигнала светофора уступить дорогу автопоезду, не успевшему совершить разворот?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>В показанной ситуации водитель синего легкового автомобиля при включении разрешающего сигнала светофора должен уступить дорогу автопоезду, завершающему разворот.</p>","image":"assets/adrive-questions/q113202002.jpg"},{"id":113202101,"themeId":3,"group":1132021,"chapter":86,"chapters":[86],"q":"При включении разрешающего сигнала в показанной обстановке кому должен предоставить преимущество водитель жёлтого легкового автомобиля, поворачивающего направо?","a":["Только пешеходам группы «А», заканчивающим переход проезжей части дороги.","Только пешеходам группы «Б», начинающим движение через проезжую часть дороги.","Водитель должен предоставить преимущество обеим группам пешеходов."],"c":2,"e":"<p>В показанной ситуации при включении разрешающего сигнала светофора водитель жёлтого легкового автомобиля, поворачивающего направо, обязан предоставить преимущество обеим группам пешеходов, как начинающим, так и заканчивающим переход проезжей части дороги.</p>","image":"assets/adrive-questions/q113202101.jpg"},{"id":113202102,"themeId":3,"group":1132021,"chapter":86,"chapters":[86],"q":"Как Вы должны поступить, подъезжая к перекрёстку при включении разрешающего сигнала в показанной ситуации?","a":["Продолжить движение, не снижая скорость.","Продолжить движение, только убедившись в отсутствии на пешеходном переходе пешеходов, не закончивших переход проезжей части дороги, а также в отсутствии транспортных средств, заканчивающих движение через перекрёсток."],"c":1,"e":"<p>В показанной ситуации, подъезжая к перекрёстку, при включении разрешающего сигнала Вы можете продолжить движение, только убедившись в отсутствии на пешеходном переходе пешеходов, не закончивших переход проезжей части дороги, а также в отсутствии транспортных средств, заканчивающих движение через перекрёсток. При их наличии — уступить дорогу транспортным средствам, завершающим движение через перекрёсток, и предоставить преимущество пешеходам, не закончившим переход проезжей части дороги.</p>","image":"assets/adrive-questions/q113202102.jpg"},{"id":113202201,"themeId":3,"group":1132022,"chapter":86,"chapters":[86],"q":"Кто в показанной ситуации имеет преимущество при проезде перекрёстка?","a":["Водитель грузового автомобиля, заканчивающий разворот на перекрёстке.","Водитель синего легкового автомобиля, начинающий движение при включении разрешающего сигнала светофора."],"c":0,"e":"<p>В показанной ситуации водитель грузового автомобиля, заканчивающий разворот на перекрёстке, имеет преимущество при проезде перекрёстка, водитель легкового автомобиля при включении разрешающего сигнала должен уступить ему дорогу.</p>","image":"assets/adrive-questions/q113202201.jpg"},{"id":113202202,"themeId":3,"group":1132022,"chapter":86,"chapters":[86],"q":"Разрешается ли в показанной ситуации проехать перекрёсток, не снижая скорости, при включении разрешающего сигнала светофора, если Вам необходимо проехать прямо?","a":["Да, разрешается.","Нет, необходимо убедиться в отсутствии пешеходов, не закончивших переход проезжей части дороги, и транспортных средств, завершающих движение через перекрёсток."],"c":1,"e":"<p>В показанной ситуации, чтобы проехать перекрёсток, необходимо убедиться в отсутствии пешеходов, не закончивших переход проезжей части дороги, и транспортных средств, завершающих движение через перекрёсток. При их наличии — уступить дорогу транспортным средствам, завершающим движение через перекрёсток, и предоставить преимущество пешеходам, не закончившим переход проезжей части дороги.</p>","image":"assets/adrive-questions/q113202202.jpg"},{"id":113202301,"themeId":3,"group":1132023,"chapter":86,"chapters":[86],"q":"Что означает информационная секция, расположенная под правой дополнительной секцией светофора?","a":["Предупреждает водителей о необходимости предоставить преимущество пешеходам.","Предупреждает о расположении пешеходной зоны справа от перекрёстка.","Предупреждает о возможном появлении пешеходов вне пешеходного перехода."],"c":0,"e":"<p>В показанной ситуации информационная секция, расположенная под правой дополнительной секцией светофора, предупреждает водителей о необходимости предоставить преимущество пешеходам.</p>","image":"assets/adrive-questions/q113202301.jpg"},{"id":113202302,"themeId":3,"group":1132023,"chapter":86,"chapters":[86],"q":"Что означает информационная табличка, расположенная под правой дополнительной секцией светофора?","a":["Предупреждает водителей о необходимости предоставить преимущество пешеходам.","Предупреждает о расположении пешеходной зоны справа от перекрёстка.","Предупреждает о расположении нескольких пешеходных переходов на участке дороги, на которую совершается поворот направо."],"c":0,"e":"<p>В показанной ситуации информационная табличка, расположенная под правой дополнительной секцией светофора, предупреждает водителей о необходимости предоставить преимущество пешеходам.</p>","image":"assets/adrive-questions/q113202302.jpg"},{"id":113300101,"themeId":3,"group":1133001,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить, двигаясь по дороге с гравийным покрытием, в показанной ситуации?","a":["Повернуть направо, пользуясь преимуществом.","Уступить дорогу грузовому автомобилю, движущемуся по дороге с асфальтобетонным покрытием."],"c":1,"e":"<p>В показанной ситуации Вы, двигаясь по дороге с гравийным покрытием, обязаны уступить дорогу грузовому автомобилю, движущемуся по дороге с асфальтобетонным покрытием.</p>","image":"assets/adrive-questions/q113300101.jpg"},{"id":113300102,"themeId":3,"group":1133001,"chapter":87,"chapters":[87],"q":"Как Вам необходимо поступить при повороте налево на показанном перекрёстке?","a":["Проехать перекрёсток первым.","Уступить дорогу красному автомобилю, подъехавшему к перекрёстку по дороге с усовершенствованным покрытием."],"c":1,"e":"<p>В показанной ситуации при повороте налево на перекрёстке необходимо уступить дорогу красному автомобилю, подъехавшему к перекрёстку по дороге с усовершенствованным покрытием.</p>","image":"assets/adrive-questions/q113300102.jpg"},{"id":113300103,"themeId":3,"group":1133001,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, намереваясь повернуть на перекрёстке налево?","a":["Проехать перекрёсток первым.","Уступить дорогу синему автомобилю, подъехавшему к перекрёстку по дороге с гравийным покрытием."],"c":0,"e":"<p>В показанной ситуации Вы, намереваясь повернуть на перекрёстке налево, имеете преимущество перед синим автомобилем, подъехавшим к перекрёстку по дороге с гравийным покрытием.</p>","image":"assets/adrive-questions/q113300103.jpg"},{"id":113300141,"themeId":3,"group":1133001,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить, приближаясь по дороге с грунтовым покрытием к необозначенному перекрёстку с дорогой с гравийным покрытием?","a":["Уступить дорогу только легковому автомобилю.","Уступить дорогу только велосипедисту.","Уступить дорогу легковому автомобилю и велосипедисту.","Пользуясь преимуществом, повернуть налево."],"c":2,"e":"<p>Дорога с гравийным покрытием является главной по отношению к дороге с грунтовым покрытием.</p> <p>Двигаясь по дороге с грунтовым покрытием, Вы обязаны уступить дорогу всем транспортным средствам, движущимся по дороге с гравийным покрытием.</p>","image":"assets/adrive-questions/q113300141.jpg"},{"id":113300201,"themeId":3,"group":1133002,"chapter":87,"chapters":[87],"q":"В показанной ситуации при движении прямо Вы:","a":["Имеете преимущество.","Должны уступить дорогу легковому автомобилю."],"c":1,"e":"<p>В показанной ситуации Вы обязаны уступить дорогу красному легковому автомобилю, так как находитесь на второстепенной дороге.</p>","image":"assets/adrive-questions/q113300201.jpg"},{"id":113300202,"themeId":3,"group":1133002,"chapter":87,"chapters":[87],"q":"Как необходимо поступить в показанной ситуации, если Вам необходимо развернуться на перекрёстке?","a":["Проехать перекрёсток первым.","Уступить дорогу водителю автобуса."],"c":0,"e":"<p>В показанной ситуации Вы имеете преимущество перед автобусом, так как находитесь на главной дороге.</p>","image":"assets/adrive-questions/q113300202.jpg"},{"id":113300301,"themeId":3,"group":1133003,"chapter":87,"chapters":[87],"q":"В показанной ситуации, подъехав к перекрёстку для дальнейшего движения прямо, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только встречному автобусу.","Обязаны уступить дорогу только грузовому автомобилю, находящемуся справа.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы имеете преимущество перед грузовым автомобилем, так как находитесь на главной дороге, водитель автобуса, поворачивая налево, обязан Вам уступить дорогу.</p>","image":"assets/adrive-questions/q113300301.jpg"},{"id":113300302,"themeId":3,"group":1133003,"chapter":87,"chapters":[87],"q":"В показанной ситуации, подъехав к перекрёстку для поворота налево, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только встречному автобусу.","Обязаны уступить дорогу только грузовому автомобилю, находящемуся слева.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы имеете преимущество перед грузовым автомобилем, так как находитесь на главной дороге, но, поворачивая налево, обязаны уступить дорогу встречному автобусу.</p>","image":"assets/adrive-questions/q113300302.jpg"},{"id":113300402,"themeId":3,"group":1133004,"chapter":87,"chapters":[87],"q":"В показанной ситуации водитель синего легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только жёлтому трамваю.","Обязан уступить дорогу только красному трамваю.","Обязан уступить дорогу обоим трамваям."],"c":2,"e":"<p>В показанной ситуации водитель синего легкового автомобиля, находясь на главной дороге, имеет преимущество перед жёлтым трамваем, но обязан уступить дорогу красному трамваю.</p>","image":"assets/adrive-questions/q113300402.jpg"},{"id":113300501,"themeId":3,"group":1133005,"chapter":87,"chapters":[87],"q":"В показанной ситуации на перекрёстке при повороте налево водитель синего автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только троллейбусу.","Должен уступить дорогу только красному легковому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации, находясь на главной дороге на перекрёстке, при повороте налево водитель синего легкового автомобиля должен уступить дорогу только встречному троллейбусу, так как тот движется прямо. Красный автомобиль находится на второстепенной дороге и обязан уступить дорогу троллейбусу и синему легковому автомобилю.</p>","image":"assets/adrive-questions/q113300501.jpg"},{"id":113300502,"themeId":3,"group":1133005,"chapter":87,"chapters":[87],"q":"В показанной ситуации, подъехав к перекрёстку для поворота налево, Вы:","a":["Имеете преимущество.","Должны уступить дорогу только красному легковому автомобилю.","Должны уступить дорогу только грузовому автомобилю, поворачивающему направо.","Должны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы вместе с грузовым и красным легковым автомобилями находитесь на главной дороге, поэтому при повороте налево обязаны уступить дорогу обоим транспортным средствам, двигающимся прямо и направо.</p>","image":"assets/adrive-questions/q113300502.jpg"},{"id":113300601,"themeId":3,"group":1133006,"chapter":87,"chapters":[87],"q":"Кому Вы обязаны уступить дорогу (предоставить преимущество) в показанной ситуации, проезжая перекрёсток в прямом направлении, если светофор не работает?","a":["Только трамваю.","Только пешеходу.","Трамваю и пешеходу.","Никому, так как имеете преимущество в показанной ситуации."],"c":1,"e":"<p>В показанной ситуации Вы находитесь на главной дороге, поэтому обязаны предоставить преимущество только пешеходу, переходящему проезжую часть дороги по пешеходному переходу.</p>","image":"assets/adrive-questions/q113300601.jpg"},{"id":113300602,"themeId":3,"group":1133006,"chapter":87,"chapters":[87],"q":"Кому обязан уступить дорогу (предоставить преимущество) водитель синего легкового автомобиля в показанной ситуации?","a":["Только трамваю.","Только пешеходу.","Трамваю и пешеходу.","Никому, так как имеет преимущество в показанной ситуации."],"c":1,"e":"<p>В показанной ситуации водитель синего легкового автомобиля находится на главной дороге, поэтому обязан предоставить преимущество только пешеходу, переходящему проезжую часть дороги по пешеходному переходу.</p>","image":"assets/adrive-questions/q113300602.jpg"},{"id":113300701,"themeId":3,"group":1133007,"chapter":87,"chapters":[87],"q":"Кому в показанной ситуации Вы обязаны уступить дорогу при повороте налево на перекрёстке?","a":["Только автобусу.","Только легковому автомобилю.","Обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации на перекрёстке при повороте налево Вы должны уступить дорогу только автобусу, так как, находясь на главной дороге при повороте налево, должны уступить дорогу встречным транспортным средствам. Водитель зелёного легкового автомобиля, находясь на второстепенной дороге, должен уступить дорогу транспортным средствам, движущимся по главной дороге.</p>","image":"assets/adrive-questions/q113300701.jpg"},{"id":113300702,"themeId":3,"group":1133007,"chapter":87,"chapters":[87],"q":"Кому в показанной ситуации Вы обязаны уступить дорогу, поворачивая налево на перекрёстке?","a":["Только грузовому автомобилю.","Только красному легковому автомобилю.","Обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации на перекрёстке при повороте налево Вы должны уступить дорогу только красному легковому автомобилю, так как, находясь на главной дороге, обязаны уступить дорогу встречному транспортному средству, поворачивающему направо. Водитель грузового автомобиля находится на второстепенной дороге и обязан уступить дорогу обоим легковым автомобилям.</p>","image":"assets/adrive-questions/q113300702.jpg"},{"id":113300801,"themeId":3,"group":1133008,"chapter":87,"chapters":[87],"q":"В показанной ситуации, поворачивая направо, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только мотоциклу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации на перекрёстке при повороте направо Вы имеете преимущество, так как находитесь на главной дороге.</p>","image":"assets/adrive-questions/q113300801.jpg"},{"id":113300802,"themeId":3,"group":1133008,"chapter":87,"chapters":[87],"q":"Какое транспортное средство в показанной ситуации должно проехать перекрёсток первым?","a":["Троллейбус.","Грузовой автомобиль.","Легковой автомобиль."],"c":1,"e":"<p>В показанной ситуации грузовой автомобиль находится на главной дороге, поэтому проедет перекрёсток первым. Водитель троллейбуса обязан уступить ему дорогу.</p>","image":"assets/adrive-questions/q113300802.jpg"},{"id":113300901,"themeId":3,"group":1133009,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации должен уступить дорогу?","a":["Водитель троллейбуса.","Водитель легкового автомобиля."],"c":0,"e":"<p>В показанной ситуации легковой автомобиль находится на главной дороге, поэтому уступить дорогу должен водитель троллейбуса.</p>","image":"assets/adrive-questions/q113300901.jpg"},{"id":113300902,"themeId":3,"group":1133009,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации имеет преимущество, если мотоциклисту необходимо повернуть направо?","a":["Мотоциклист.","Водитель автобуса."],"c":0,"e":"<p>В показанной ситуации мотоциклист находится на главной дороге, поэтому уступить дорогу должен водитель автобуса.</p>","image":"assets/adrive-questions/q113300902.jpg"},{"id":113301001,"themeId":3,"group":1133010,"chapter":87,"chapters":[87],"q":"Водитель грузового автомобиля проедет перекрёсток:","a":["Первым.","Вторым после проезда трамвая.","Вторым после проезда трамвая и троллейбуса, которые проедут перекрёсток одновременно."],"c":0,"e":"<p>В показанной ситуации грузовой автомобиль находится на главной дороге, поэтому проедет перекрёсток первым.</p>","image":"assets/adrive-questions/q113301001.jpg"},{"id":113301002,"themeId":3,"group":1133010,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу жёлтому трамваю.","Должен уступить дорогу обоим трамваям."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля и жёлтого трамвая находятся на главной дороге, поэтому при повороте налево водитель легкового автомобиля должен уступить дорогу только жёлтому трамваю.</p>","image":"assets/adrive-questions/q113301002.jpg"},{"id":113301101,"themeId":3,"group":1133011,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу красному трамваю.","Должен уступить дорогу обоим трамваям."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля и зелёного трамвая находятся на второстепенной дороге, поэтому при повороте налево водитель легкового автомобиля должен уступить дорогу обоим трамваям.</p>","image":"assets/adrive-questions/q113301101.jpg"},{"id":113301102,"themeId":3,"group":1133011,"chapter":87,"chapters":[87],"q":"Намереваясь двигаться прямо, Вы должны проехать перекрёсток:","a":["Первым.","Вторым после проезда трамвая.","Вторым после проезда трамвая и троллейбуса, которые проедут перекрёсток одновременно."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому должны проехать перекрёсток вторым после проезда трамвая и троллейбуса.</p>","image":"assets/adrive-questions/q113301102.jpg"},{"id":113301201,"themeId":3,"group":1133012,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации Вы:","a":["Имеете преимущество.","Должны уступить дорогу только грузовому автомобилю.","Должны уступить дорогу только гужевому транспортному средству.","Должны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы, управляя легковым автомобилем и поворачивая налево, находитесь на второстепенной дороге и обязаны уступить дорогу как грузовому автомобилю, движущемуся по главной дороге, так и гужевому ТС, движущемуся прямо по второстепенной дороге.</p>","image":"assets/adrive-questions/q113301201.jpg"},{"id":113301202,"themeId":3,"group":1133012,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, поворачивая налево?","a":["Пользуясь преимуществом, первым проехать перекрёсток.","Уступить дорогу мопеду."],"c":1,"e":"<p>В показанной ситуации при повороте налево Вы должны уступить дорогу водителю мопеда, движущемуся прямо.</p>","image":"assets/adrive-questions/q113301202.jpg"},{"id":113301301,"themeId":3,"group":1133013,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, двигаясь через перекрёсток в прямом направлении?","a":["Пользуясь преимуществом, первым проехать перекрёсток.","Уступить дорогу мопеду."],"c":1,"e":"<p>В показанной ситуации, находясь на второстепенной дороге, Вы должны уступить дорогу водителю мопеда, движущемуся по главной дороге.</p>","image":"assets/adrive-questions/q113301301.jpg"},{"id":113301302,"themeId":3,"group":1133013,"chapter":87,"chapters":[87],"q":"При повороте направо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу только гужевому транспортному средству.","Должен уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на второстепенной дороге, поэтому при повороте направо должен уступить дорогу только гужевому транспортному средству, находящемуся на главной дороге.</p>","image":"assets/adrive-questions/q113301302.jpg"},{"id":113301401,"themeId":3,"group":1133014,"chapter":87,"chapters":[87],"q":"В показанной ситуации, двигаясь прямо на перекрёстке, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только встречному автобусу.","Обязаны уступить дорогу только грузовому автомобилю, находящемуся справа.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы, управляя легковым автомобилем, находитесь на главной дороге, поэтому при движении прямо имеете преимущество. Водитель автобуса, поворачивая налево, обязан уступить Вам дорогу.</p>","image":"assets/adrive-questions/q113301401.jpg"},{"id":113301402,"themeId":3,"group":1133014,"chapter":87,"chapters":[87],"q":"Кому Вы обязаны уступить дорогу (предоставить преимущество), двигаясь прямо на перекрёстке, в показанной ситуации?","a":["Только трамваю.","Только пешеходу.","Трамваю и пешеходу."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому обязаны предоставить преимущество пешеходу, переходящему проезжую часть по пешеходному переходу, и уступить дорогу трамваю.</p>","image":"assets/adrive-questions/q113301402.jpg"},{"id":113301501,"themeId":3,"group":1133015,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации имеет преимущество, если мотоциклисту необходимо повернуть направо?","a":["Мотоциклист.","Водитель автобуса."],"c":1,"e":"<p>В показанной ситуации водитель мотоцикла находится на второстепенной дороге, поэтому должен уступить дорогу автобусу.</p>","image":"assets/adrive-questions/q113301501.jpg"},{"id":113301502,"themeId":3,"group":1133015,"chapter":87,"chapters":[87],"q":"Кому в показанной обстановке должен уступить дорогу водитель легкового автомобиля?","a":["Только трамваю.","Только автобусу.","Трамваю и автобусу."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на второстепенной дороге, поэтому при повороте направо должен уступить дорогу трамваю и автобусу.</p>","image":"assets/adrive-questions/q113301502.jpg"},{"id":113301601,"themeId":3,"group":1133016,"chapter":87,"chapters":[87],"q":"Водитель грузового автомобиля проедет перекрёсток:","a":["Первым.","Вторым после проезда трамвая.","Вторым после проезда трамвая и троллейбуса, которые проедут перекрёсток одновременно."],"c":2,"e":"<p>В показанной ситуации водитель грузового автомобиля находится на второстепенной дороге, поэтому проедет перекрёсток вторым после проезда трамвая и троллейбуса.</p>","image":"assets/adrive-questions/q113301601.jpg"},{"id":113301602,"themeId":3,"group":1133016,"chapter":87,"chapters":[87],"q":"Как в показанной ситуации Вы обязаны поступить, поворачивая налево на перекрёстке?","a":["Уступить дорогу только троллейбусу.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при повороте налево должны уступить дорогу грузовому автомобилю, находящемуся на главной дороге, и троллейбусу, движущемуся прямо по второстепенной дороге.</p>","image":"assets/adrive-questions/q113301602.jpg"},{"id":113301701,"themeId":3,"group":1133017,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить, совершая поворот налево, в показанной обстановке?","a":["Проехать перекрёсток первым.","Уступить дорогу легковому автомобилю."],"c":1,"e":"<p>В показанной ситуации Вы, совершая поворот налево, находитесь на второстепенной дороге, поэтому должны уступить дорогу.</p>","image":"assets/adrive-questions/q113301701.jpg"},{"id":113301702,"themeId":3,"group":1133017,"chapter":87,"chapters":[87],"q":"В показанной ситуации, подъехав к перекрёстку для поворота налево, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу, находящемуся слева.","Обязаны уступить дорогу только встречному грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы, находясь на второстепенной дороге, обязаны уступить дорогу транспортному средству, находящемуся на главной дороге, и при повороте налево — транспортному средству, движущемуся прямо.</p>","image":"assets/adrive-questions/q113301702.jpg"},{"id":113301801,"themeId":3,"group":1133018,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, поворачивая налево на перекрёстке?","a":["Уступить дорогу только трактору.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу только трактору и грузовому автомобилю.","Уступить дорогу всем транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы, находясь на второстепенной дороге, обязаны уступить дорогу транспортным средствам, находящимся на главной дороге, и, поворачивая налево, — транспортному средству, движущемуся прямо.</p>","image":"assets/adrive-questions/q113301801.jpg"},{"id":113301802,"themeId":3,"group":1133018,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, поворачивая налево на перекрёстке?","a":["Пользуясь преимуществом, проехать перекрёсток первым.","Уступить дорогу только автобусу.","Уступить дорогу только автобусу и трактору.","Уступить дорогу только трактору и грузовому автомобилю.","Уступить дорогу всем транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы находитесь на главной дороге и, поворачивая налево, обязаны уступить дорогу автобусу, двигающемуся прямо.</p>","image":"assets/adrive-questions/q113301802.jpg"},{"id":113301803,"themeId":3,"group":1133018,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить в показанной ситуации, двигаясь прямо на перекрёстке:","a":["Уступить дорогу только трактору.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу только трактору и грузовому автомобилю.","Уступить дорогу всем транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при движении прямо должны уступить дорогу только трактору и грузовому автомобилю, подъехавшим к перекрёстку по главной дороге.</p>","image":"assets/adrive-questions/q113301803.jpg"},{"id":113301901,"themeId":3,"group":1133019,"chapter":87,"chapters":[87],"q":"В показанной ситуации водитель грузового автомобиля:","a":["Имеет преимущество, находясь на главной дороге.","Должен уступить дорогу только транспортному средству оперативного назначения.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации водитель грузового автомобиля, несмотря на то, что находится на главной дороге, должен уступить дорогу транспортному средству оперативного назначения с включённым маячком синего цвета.</p>","image":"assets/adrive-questions/q113301901.jpg"},{"id":113301902,"themeId":3,"group":1133019,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить, если Вы намерены продолжить на перекрёстке движение прямо?","a":["Проехать перекрёсток первым.","Уступить дорогу только транспортному средству оперативного назначения.","Уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с автобусом находитесь на главной дороге, однако необходимо уступить дорогу ТС оперативного назначения с включённым маячком синего цвета. Автобусу также следует уступить дорогу, так как он приближается справа.</p>","image":"assets/adrive-questions/q113301902.jpg"},{"id":113302001,"themeId":3,"group":1133020,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге вместе с водителем автобуса, но должен уступить дорогу водителю автобуса, так как тот приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113302001.jpg"},{"id":113302002,"themeId":3,"group":1133020,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить в показанной ситуации, двигаясь на перекрёстке прямо?","a":["Проехать перекрёсток первым.","Уступить дорогу только автобусу.","Уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге вместе с водителем автобуса, но должен уступить дорогу водителю автобуса, так как тот приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113302002.jpg"},{"id":113302101,"themeId":3,"group":1133021,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить в показанной ситуации, двигаясь на перекрёстке прямо?","a":["Проехать перекрёсток первым.","Уступить дорогу только трактору.","Уступить дорогу только автобусу.","Уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы находитесь на главной дороге вместе с водителем колёсного трактора, но имеете преимущество, находясь справа от колёсного трактора.</p>","image":"assets/adrive-questions/q113302101.jpg"},{"id":113302102,"themeId":3,"group":1133021,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только трактору.","Обязан уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге вместе с водителем колёсного трактора, но имеет преимущество, так как находится справа от колёсного трактора.</p>","image":"assets/adrive-questions/q113302102.jpg"},{"id":113302201,"themeId":3,"group":1133022,"chapter":87,"chapters":[87],"q":"В показанной ситуации водитель красного легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только зелёному легковому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации все транспортные средства находятся на главной дороге, поэтому водитель красного легкового автомобиля должен уступить дорогу трамваю и зелёному легковому автомобилю, так как в равных условиях трамвай пользуется преимуществом, а зелёный автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113302201.jpg"},{"id":113302202,"themeId":3,"group":1133022,"chapter":87,"chapters":[87],"q":"В показанной ситуации водитель красного легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только зелёному легковому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации водитель красного легкового автомобиля и трамвая находятся на главной дороге, поэтому при повороте налево водитель красного легкового автомобиля обязан уступить дорогу только трамваю.</p>","image":"assets/adrive-questions/q113302202.jpg"},{"id":113302301,"themeId":3,"group":1133023,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только трактору.","Обязан уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля, находясь на второстепенной дороге, обязан уступить дорогу колёсному трактору, находящемуся на главной дороге, и автобусу, приближающемуся справа по второстепенной дороге.</p>","image":"assets/adrive-questions/q113302301.jpg"},{"id":113302302,"themeId":3,"group":1133023,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только трактору.","Обязан уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля, находясь на второстепенной дороге, обязан уступить дорогу колёсному трактору, находящемуся на главной дороге, и автобусу, приближающемуся справа по второстепенной дороге.</p>","image":"assets/adrive-questions/q113302302.jpg"},{"id":113302401,"themeId":3,"group":1133024,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу только грузовому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля, находясь на второстепенной дороге, обязан уступить дорогу автобусу, находящемуся на главной дороге, и грузовому автомобилю, приближающемуся справа по второстепенной дороге.</p>","image":"assets/adrive-questions/q113302401.jpg"},{"id":113302402,"themeId":3,"group":1133024,"chapter":87,"chapters":[87],"q":"Водитель легкового автомобиля в показанной ситуации:","a":["Имеет преимущество.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу только грузовому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля, находясь на второстепенной дороге, обязан уступить дорогу автобусу, находящемуся на главной дороге, и грузовому автомобилю, приближающемуся справа по второстепенной дороге.</p>","image":"assets/adrive-questions/q113302402.jpg"},{"id":113302501,"themeId":3,"group":1133025,"chapter":87,"chapters":[87],"q":"При проезде показанного на рисунке перекрёстка водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль вместе с автобусом и трамваем находятся на главной дороге, поэтому водитель синего легкового автомобиля обязан уступить дорогу только трамваю, так как трамвай в равных условиях пользуется преимуществом, а автобус находится слева от легкового автомобиля.</p>","image":"assets/adrive-questions/q113302501.jpg"},{"id":113302502,"themeId":3,"group":1133025,"chapter":87,"chapters":[87],"q":"При проезде показанного на рисунке перекрёстка водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге, поэтому имеет преимущество.</p>","image":"assets/adrive-questions/q113302502.jpg"},{"id":113302601,"themeId":3,"group":1133026,"chapter":87,"chapters":[87],"q":"При проезде показанного на рисунке перекрёстка водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации легковой автомобиль вместе с автобусом и трамваем находятся на главной дороге, поэтому водитель синего легкового автомобиля обязан уступить дорогу обоим транспортным средствам, так как автобус приближается справа, а трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113302601.jpg"},{"id":113302602,"themeId":3,"group":1133026,"chapter":87,"chapters":[87],"q":"При проезде показанного на рисунке перекрёстка водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге вместе с автобусом, поэтому при движении прямо обязан уступить дорогу только автобусу, так как автобус приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113302602.jpg"},{"id":113302701,"themeId":3,"group":1133027,"chapter":87,"chapters":[87],"q":"При повороте направо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому обязаны уступить дорогу только автобусу, так как находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113302701.jpg"},{"id":113302702,"themeId":3,"group":1133027,"chapter":87,"chapters":[87],"q":"Двигаясь прямо через перекрёсток, Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при движении прямо обязаны уступить дорогу обоим транспортным средствам, находящимся на главной дороге.</p>","image":"assets/adrive-questions/q113302702.jpg"},{"id":113302762,"themeId":3,"group":1133027,"chapter":87,"chapters":[87],"q":"На перекрёстке Вы намерены повернуть направо. Как следует поступить в показанной ситуации?","a":["Уступить дорогу белому легковому автомобилю.","Пользуясь преимуществом, первым проехать перекрёсток."],"c":0,"e":"<p>Встречный автомобиль, двигаясь по дороге с односторонним движением, поворачивает налево из крайней левой полосы движения.</p> <p>Находясь на второстепенной дороге, Вы обязаны уступить дорогу встречному легковому автомобилю, движущемуся по главной дороге.</p>","image":"assets/adrive-questions/q113302762.jpg"},{"id":113302801,"themeId":3,"group":1133028,"chapter":87,"chapters":[87],"q":"При повороте налево водитель синего легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации синий легковой автомобиль вместе с красным легковым автомобилем и трамваем находятся на второстепенной дороге, поэтому водитель синего легкового автомобиля обязан уступить дорогу обоим транспортным средствам, так как красный легковой автомобиль приближается справа, а трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113302801.jpg"},{"id":113302802,"themeId":3,"group":1133028,"chapter":87,"chapters":[87],"q":"Вы, намереваясь проехать перекрёсток прямо, в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только трамваю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при движении прямо обязаны уступить дорогу обоим транспортным средствам, находящимся на главной дороге.</p>","image":"assets/adrive-questions/q113302802.jpg"},{"id":113302851,"themeId":3,"group":1133028,"chapter":87,"chapters":[87],"q":"В показанной ситуации при неработающих светофорах, двигаясь на перекрёстке прямо, Вы:","a":["Имеете преимущество.","Должны уступить дорогу только трамваю.","Должны уступить дорогу трамваю и грузопассажирскому фургону."],"c":2,"e":"<p>При неработающих светофорах очерёдность проезда перекрёстка определяется знаками приоритета.</p> <p>Находясь на второстепенной дороге, Вы обязаны уступить дорогу всем транспортным средствам, находящимся на главной дороге, независимо от направления их дальнейшего движения.</p>","image":"assets/adrive-questions/q113302851.jpg"},{"id":113302901,"themeId":3,"group":1133029,"chapter":87,"chapters":[87],"q":"При повороте направо Вы, управляя легковым автомобилем:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только мотоциклу.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы находитесь на главной дороге, поэтому имеете преимущество.</p>","image":"assets/adrive-questions/q113302901.jpg"},{"id":113302902,"themeId":3,"group":1133029,"chapter":87,"chapters":[87],"q":"Какое транспортное средство в показанной ситуации должно проехать перекрёсток первым?","a":["Автобус.","Мотоцикл.","Грузовой автомобиль."],"c":1,"e":"<p>В показанной ситуации водитель мотоцикла находится на главной дороге, поэтому проедет перекрёсток первым.</p>","image":"assets/adrive-questions/q113302902.jpg"},{"id":113303001,"themeId":3,"group":1133030,"chapter":87,"chapters":[87],"q":"При повороте направо в показанной ситуации водитель грузового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только легковому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель грузового автомобиля находится на главной дороге вместе с легковым автомобилем, поэтому при повороте направо имеет преимущество, так как находится справа от легкового автомобиля.</p>","image":"assets/adrive-questions/q113303001.jpg"},{"id":113303101,"themeId":3,"group":1133031,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль и трамвай находятся на главной дороге, поэтому при повороте налево водитель легкового автомобиля должен уступить дорогу только трамваю.</p>","image":"assets/adrive-questions/q113303101.jpg"},{"id":113303102,"themeId":3,"group":1133031,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем находятся на главной дороге, поэтому при повороте налево водитель легкового автомобиля имеет преимущество, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113303102.jpg"},{"id":113303161,"themeId":3,"group":1133031,"chapter":87,"chapters":[87],"q":"Как должен поступить в показанной ситуации водитель легкового автомобиля, намереваясь повернуть на перекрёстке налево?","a":["Проехать перекрёсток первым.","Уступить дорогу только трамваю.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу трамваю и грузовому автомобилю."],"c":0,"e":"<p>Находясь на главной дороге, водитель синего легкового автомобиля имеет преимущество перед трамваем, находящимся на второстепенной дороге, и при этом также имеет преимущество перед грузовым автомобилем, который находится на главной дороге, но подъехал к перекрёстку слева.</p>","image":"assets/adrive-questions/q113303161.jpg"},{"id":113303201,"themeId":3,"group":1133032,"chapter":87,"chapters":[87],"q":"В показанной ситуации при проезде перекрёстка прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль находится на второстепенной дороге вместе с грузовым автомобилем, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу только трамваю, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113303201.jpg"},{"id":113303301,"themeId":3,"group":1133033,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель автобуса.","Водитель легкового автомобиля."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на второстепенной дороге, поэтому должен уступить дорогу автобусу.</p>","image":"assets/adrive-questions/q113303301.jpg"},{"id":113303501,"themeId":3,"group":1133035,"chapter":87,"chapters":[87],"q":"На светофоре включён жёлтый мигающий сигнал. В сложившейся обстановке водитель легкового автомобиля при повороте налево:","a":["Имеет преимущество.","Должен уступить дорогу только автобусу.","Должен уступить дорогу только трамваю.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации на светофоре включён жёлтый мигающий сигнал и водитель легкового автомобиля вместе с трамваем находится на второстепенной дороге, поэтому при повороте налево он должен уступить дорогу обоим транспортным средствам.</p>","image":"assets/adrive-questions/q113303501.jpg"},{"id":113303502,"themeId":3,"group":1133035,"chapter":87,"chapters":[87],"q":"На светофоре включён жёлтый мигающий сигнал. В сложившейся обстановке водитель легкового автомобиля при повороте налево:","a":["Имеет преимущество.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу обоим трамваям."],"c":3,"e":"<p>В показанной ситуации на светофоре включён жёлтый мигающий сигнал. Легковой автомобиль вместе с трамваями находится на второстепенной дороге, поэтому водитель синего автомобиля при повороте налево обязан уступить дорогу обоим трамваям, так как трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113303502.jpg"},{"id":113303601,"themeId":3,"group":1133036,"chapter":87,"chapters":[87],"q":"На светофоре включён жёлтый мигающий сигнал. В сложившейся обстановке водитель легкового автомобиля при движении прямо:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только автобусу.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации на светофоре включён жёлтый мигающий сигнал. Легковой автомобиль и трамвай находятся на главной дороге, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу только трамваю.</p>","image":"assets/adrive-questions/q113303601.jpg"},{"id":113303602,"themeId":3,"group":1133036,"chapter":87,"chapters":[87],"q":"На светофоре включён жёлтый мигающий сигнал. В сложившейся обстановке водитель легкового автомобиля при движении прямо:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только автобусу.","Должен уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации на светофоре включён жёлтый мигающий сигнал и водитель легкового автомобиля находится на главной дороге вместе с автобусом, поэтому при движении прямо должен уступить дорогу только автобусу, так как автобус приближается справа.</p>","image":"assets/adrive-questions/q113303602.jpg"},{"id":113303661,"themeId":3,"group":1133036,"chapter":87,"chapters":[87],"q":"Как должен поступить в показанной ситуации водитель легкового автомобиля, намереваясь повернуть на перекрёстке направо?","a":["Проехать перекрёсток первым.","Уступить дорогу только трамваю.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу трамваю и грузовому автомобилю."],"c":1,"e":"<p>При неработающих светофорах очерёдность проезда перекрёстка определяется знаками приоритета.</p> <p>Водитель белого легкового автомобиля должен уступить дорогу трамваю, который имеет преимущество, находясь в равных с ним условиях.</p> <p>Водитель грузового автомобиля, находящийся на второстепенной дороге, обязан уступить дорогу легковому автомобилю.</p>","image":"assets/adrive-questions/q113303661.jpg"},{"id":113303801,"themeId":3,"group":1133038,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трактору.","Должен уступить дорогу только автобусу.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге, поэтому имеет преимущество.</p>","image":"assets/adrive-questions/q113303801.jpg"},{"id":113303802,"themeId":3,"group":1133038,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только автобусу.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу только гужевому транспортному средству.","Должен уступить дорогу всем транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге вместе с гужевым транспортным средством, поэтому имеет преимущество, так как находится справа от гужевого ТС.</p>","image":"assets/adrive-questions/q113303802.jpg"},{"id":113303901,"themeId":3,"group":1133039,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте направо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу автобусу."],"c":0,"e":"<p>В показанной ситуации водитель синего легкового автомобиля вместе с автобусом находятся на второстепенной дороге, поэтому водитель синего автомобиля имеет преимущество, так как легковой автомобиль находится справа от автобуса.</p>","image":"assets/adrive-questions/q113303901.jpg"},{"id":113303902,"themeId":3,"group":1133039,"chapter":87,"chapters":[87],"q":"Каким по очереди должен проехать перекрёсток водитель синего автомобиля в сложившейся обстановке, если водитель красного автомобиля намерен развернуться?","a":["Первым.","Вторым, после проезда красного автомобиля."],"c":1,"e":"<p>В показанной ситуации водитель красного легкового автомобиля находится на главной дороге и намерен развернуться, поэтому водитель синего легкового автомобиля должен проехать перекрёсток вторым, после проезда красного автомобиля.</p>","image":"assets/adrive-questions/q113303902.jpg"},{"id":113304001,"themeId":3,"group":1133040,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) водитель легкового автомобиля находится на второстепенной дороге, поэтому при повороте налево должен уступить дорогу обоим транспортным средствам, находящимся на главной дороге.</p>","image":"assets/adrive-questions/q113304001.jpg"},{"id":113304101,"themeId":3,"group":1133041,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) водитель легкового автомобиля находится на главной дороге вместе с грузовым автомобилем, поэтому при движении прямо имеет преимущество, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113304101.jpg"},{"id":113304102,"themeId":3,"group":1133041,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) водитель легкового автомобиля и трамвая находятся на главной дороге, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу только трамваю.</p>","image":"assets/adrive-questions/q113304102.jpg"},{"id":113304151,"themeId":3,"group":1133041,"chapter":87,"chapters":[87],"q":"Как должен поступить в показанной ситуации водитель легкового автомобиля, намереваясь повернуть на перекрёстке направо?","a":["Проехать перекрёсток первым.","Уступить дорогу только трамваю.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу трамваю и грузовому автомобилю."],"c":1,"e":"<p>При неработающих светофорах очерёдность проезда перекрёстка определяется знаками приоритета.</p> <p>Все транспортные средства находятся на главной дороге, то есть в равных условиях.</p> <p>Водитель красного легкового автомобиля должен уступить дорогу трамваю, который имеет преимущество в равных с ним условиях, а водитель грузового автомобиля, находящийся слева, обязан уступить дорогу легковому автомобилю.</p>","image":"assets/adrive-questions/q113304151.jpg"},{"id":113304201,"themeId":3,"group":1133042,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации обязан уступить дорогу?","a":["Водитель мотоцикла.","Водитель легкового автомобиля."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на второстепенной дороге, поэтому должен уступить мотоциклисту.</p>","image":"assets/adrive-questions/q113304201.jpg"},{"id":113304202,"themeId":3,"group":1133042,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при повороте направо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только троллейбусу.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с трамваем находятся на второстепенной дороге, поэтому водитель легкового автомобиля должен уступить и троллейбусу, движущемуся по главной дороге, и трамваю.</p>","image":"assets/adrive-questions/q113304202.jpg"},{"id":113304301,"themeId":3,"group":1133043,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только троллейбусу.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с трамваем находятся на второстепенной дороге, поэтому водитель легкового автомобиля должен уступить и троллейбусу, движущемуся по главной дороге, и трамваю.</p>","image":"assets/adrive-questions/q113304301.jpg"},{"id":113304302,"themeId":3,"group":1133043,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только колёсному трактору.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с колёсным трактором находятся на второстепенной дороге, поэтому водитель легкового автомобиля должен уступить и грузовому автомобилю, движущемуся по главной дороге, и колёсному трактору, приближающемуся справа.</p>","image":"assets/adrive-questions/q113304302.jpg"},{"id":113304401,"themeId":3,"group":1133044,"chapter":87,"chapters":[87],"q":"Вы подъехали к перекрёстку для поворота налево. Вы в показанной ситуации:","a":["Пользуетесь преимуществом.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только колёсному трактору.","Обязаны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с автобусом находитесь на второстепенной дороге, поэтому при повороте налево должны уступить дорогу только колёсному трактору, так как находитесь справа от автобуса.</p>","image":"assets/adrive-questions/q113304401.jpg"},{"id":113304402,"themeId":3,"group":1133044,"chapter":87,"chapters":[87],"q":"Вы подъехали к перекрёстку для поворота налево. Вы в показанной ситуации:","a":["Пользуетесь преимуществом.","Обязаны уступить дорогу только самоходной машине.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при повороте налево должны уступить дорогу грузовому автомобилю и самоходной машине.</p>","image":"assets/adrive-questions/q113304402.jpg"},{"id":113304501,"themeId":3,"group":1133045,"chapter":87,"chapters":[87],"q":"Вы подъехали к перекрёстку для дальнейшего движения прямо, но светофор не работает. Вы в показанной ситуации:","a":["Пользуетесь преимуществом.","Обязаны уступить дорогу только трамваю.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации (светофор не работает) Вы вместе с грузовым автомобилем находитесь на второстепенной дороге, поэтому при движении прямо должны уступить дорогу трамваю и грузовому автомобилю, так как он приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113304501.jpg"},{"id":113304502,"themeId":3,"group":1133045,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только троллейбусу.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с трамваем находятся на второстепенной дороге, поэтому водитель легкового автомобиля должен уступить и троллейбусу, движущемуся по главной дороге, и трамваю.</p>","image":"assets/adrive-questions/q113304502.jpg"},{"id":113304601,"themeId":3,"group":1133046,"chapter":87,"chapters":[87],"q":"В показанной ситуации при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только автобусу.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем находятся на главной дороге, поэтому при движении прямо водитель легкового автомобиля имеет преимущество, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113304601.jpg"},{"id":113304602,"themeId":3,"group":1133046,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево Вы, управляя легковым автомобилем:","a":["Имеете преимущество.","Должны уступить дорогу только автобусу.","Должны уступить дорогу только грузовому автомобилю.","Должны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы подъезжаете к перекрёстку вместе с грузовым автомобилем по главной дороге, поэтому при повороте налево имеете преимущество, так как находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113304602.jpg"},{"id":113304702,"themeId":3,"group":1133047,"chapter":87,"chapters":[87],"q":"Как Вы должны поступить, подъехав к перекрёстку для поворота направо в показанной ситуации, если водитель грузового автомобиля намерен развернуться на перекрёстке?","a":["Пользуясь преимуществом, повернуть направо.","Повернуть направо в момент, когда грузовой автомобиль выедет на перекрёсток.","Повернуть направо только после завершения выполнения разворота грузовым автомобилем."],"c":2,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому должны повернуть направо только после завершения выполнения разворота грузовым автомобилем.</p>","image":"assets/adrive-questions/q113304702.jpg"},{"id":113304801,"themeId":3,"group":1133048,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу обоим трамваям."],"c":3,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) водитель легкового автомобиля вместе с жёлтым трамваем находятся на второстепенной дороге, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу обоим трамваям.</p>","image":"assets/adrive-questions/q113304801.jpg"},{"id":113304802,"themeId":3,"group":1133048,"chapter":87,"chapters":[87],"q":"В показанной ситуации при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только колёсному трактору.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль и грузовой автомобиль находятся на второстепенной дороге, поэтому при движении прямо водитель легкового автомобиля, так как находится справа от грузового автомобиля, должен уступить дорогу только колёсному трактору.</p>","image":"assets/adrive-questions/q113304802.jpg"},{"id":113304901,"themeId":3,"group":1133049,"chapter":87,"chapters":[87],"q":"Намереваясь продолжать движение прямо, Вы в показанной ситуации (на светофоре включён жёлтый мигающий сигнал):","a":["Имеете преимущество.","Должны уступить дорогу только трамваю.","Должны уступить дорогу только автобусу.","Должны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) Вы вместе с автобусом находитесь на главной дороге, поэтому при движении прямо имеете преимущество, так как находитесь справа от автобуса.</p>","image":"assets/adrive-questions/q113304901.jpg"},{"id":113304902,"themeId":3,"group":1133049,"chapter":87,"chapters":[87],"q":"Намереваясь продолжать движение прямо, Вы в показанной ситуации (на светофоре включён жёлтый мигающий сигнал):","a":["Имеете преимущество.","Должны уступить дорогу только трамваю.","Должны уступить дорогу только автобусу.","Должны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) Вы находитесь на главной дороге, поэтому при движении прямо имеете преимущество.</p>","image":"assets/adrive-questions/q113304902.jpg"},{"id":113305001,"themeId":3,"group":1133050,"chapter":87,"chapters":[87],"q":"В показанной ситуации при движении прямо Вы, управляя легковым автомобилем:","a":["Имеете преимущество.","Должны уступить дорогу только автобусу.","Должны уступить дорогу только грузовому автомобилю.","Должны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на главной дороге, поэтому при движении прямо должны уступить дорогу только грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113305001.jpg"},{"id":113305002,"themeId":3,"group":1133050,"chapter":87,"chapters":[87],"q":"В показанной ситуации при движении прямо водитель легкового автомобиля с прицепом:","a":["Имеет преимущество.","Должен уступить дорогу только автобусу.","Должен уступить дорогу только колёсному трактору.","Должен уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации легковой автомобиль с прицепом вместе с колёсным трактором находятся на главной дороге, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу только колёсному трактору, так как колёсный трактор приближается справа.</p>","image":"assets/adrive-questions/q113305002.jpg"},{"id":113305101,"themeId":3,"group":1133051,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля с прицепом:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации легковой автомобиль с прицепом вместе с грузовым автомобилем находятся на главной дороге, поэтому при повороте налево водитель легкового автомобиля имеет преимущество, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113305101.jpg"},{"id":113305102,"themeId":3,"group":1133051,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля с прицепом:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля с прицепом находится на главной дороге, поэтому при повороте налево имеет преимущество.</p>","image":"assets/adrive-questions/q113305102.jpg"},{"id":113305201,"themeId":3,"group":1133052,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля с прицепом:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации легковой автомобиль с прицепом вместе с трамваем находятся на второстепенной дороге, поэтому при повороте налево водитель легкового автомобиля должен уступить дорогу грузовому автомобилю и трамваю, так как трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113305201.jpg"},{"id":113305202,"themeId":3,"group":1133052,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля с прицепом:","a":["Имеет преимущество.","Должен уступить дорогу только трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации водитель легкового автомобиля с прицепом находится на второстепенной дороге, поэтому при повороте налево должен уступить дорогу обоим транспортным средствам, движущимся по главной дороге.</p>","image":"assets/adrive-questions/q113305202.jpg"},{"id":113305301,"themeId":3,"group":1133053,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только колёсному трактору.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге, поэтому при повороте налево имеет преимущество.</p>","image":"assets/adrive-questions/q113305301.jpg"},{"id":113305302,"themeId":3,"group":1133053,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только колёсному трактору.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге, поэтому при повороте налево имеет преимущество.</p>","image":"assets/adrive-questions/q113305302.jpg"},{"id":113305401,"themeId":3,"group":1133054,"chapter":87,"chapters":[87],"q":"Вы подъехали к перекрёстку для поворота налево. В показанной ситуации Вы:","a":["Пользуетесь преимуществом.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на главной дороге, поэтому при повороте налево обязаны уступить дорогу только грузовому автомобилю, так как грузовой автомобиль приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113305401.jpg"},{"id":113305402,"themeId":3,"group":1133054,"chapter":87,"chapters":[87],"q":"В показанной ситуации при повороте налево водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только автобусу.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем находятся на главной дороге, поэтому при повороте налево водитель легкового автомобиля должен уступить дорогу, так как грузовой автомобиль приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113305402.jpg"},{"id":113305501,"themeId":3,"group":1133055,"chapter":87,"chapters":[87],"q":"В показанной ситуации при выезде на перекрёсток с круговым движением водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на второстепенной дороге, поэтому при въезде на перекрёсток с круговым движением должен уступить дорогу грузовому автомобилю.</p>","image":"assets/adrive-questions/q113305501.jpg"},{"id":113305502,"themeId":3,"group":1133055,"chapter":87,"chapters":[87],"q":"Кто в показанной ситуации должен уступить дорогу?","a":["Водитель грузового автомобиля.","Водитель легкового автомобиля."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля находится на главной дороге, поэтому уступить дорогу должен водитель грузового автомобиля, находящийся на второстепенной дороге.</p>","image":"assets/adrive-questions/q113305502.jpg"},{"id":113305601,"themeId":3,"group":1133056,"chapter":87,"chapters":[87],"q":"Вы подъехали к перекрёстку для дальнейшего движения прямо. В показанной ситуации Вы:","a":["Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только колёсному трактору.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу только колёсному трактору и грузовому автомобилю.","Обязаны уступить дорогу всем транспортным средствам."],"c":4,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому обязаны уступить дорогу всем транспортным средствам, в том числе автобусу, приближающемуся по второстепенной дороге справа.</p>","image":"assets/adrive-questions/q113305601.jpg"},{"id":113305602,"themeId":3,"group":1133056,"chapter":87,"chapters":[87],"q":"При движении прямо Вы в показанной ситуации:","a":["Должны уступить дорогу только автобусу.","Должны уступить дорогу только колёсному трактору.","Должен уступить дорогу только грузовому автомобилю.","Должны уступить дорогу только колёсному трактору и грузовому автомобилю.","Должны уступить дорогу всем транспортным средствам."],"c":4,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге, поэтому при движении прямо обязаны уступить дорогу всем транспортным средствам, в том числе автобусу, приближающемуся по второстепенной дороге справа.</p>","image":"assets/adrive-questions/q113305602.jpg"},{"id":113305701,"themeId":3,"group":1133057,"chapter":87,"chapters":[87],"q":"Каким образом Вы должны проехать перекрёсток, поворачивая налево, в показанной обстановке?","a":["Только после проезда синего автомобиля.","Первым, одновременно с зелёным автомобилем."],"c":0,"e":"<p>В показанной ситуации Вы находитесь на второстепенной дороге и, учитывая, что траектории с зелёным легковым автомобилем у Вас не пересекаются, можете проехать перекрёсток, поворачивая налево, после проезда синего автомобиля.</p>","image":"assets/adrive-questions/q113305701.jpg"},{"id":113305702,"themeId":3,"group":1133057,"chapter":87,"chapters":[87],"q":"Вы, поворачивая налево на показанном перекрёстке, должны проехать перекрёсток:","a":["Первым.","Вторым.","Третьим."],"c":1,"e":"<p>В показанной ситуации Вы вместе с синим легковым автомобилем находитесь на главной дороге, поэтому проехать перекрёсток, поворачивая налево, должны вторым, так как синий легковой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113305702.jpg"},{"id":113305801,"themeId":3,"group":1133058,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить в показанной ситуации, двигаясь прямо через перекрёсток?","a":["Первым проехать перекрёсток.","Уступить дорогу только автобусу.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу только автобусу и грузовому автомобилю.","Уступить дорогу всем транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы вместе с автобусом находитесь на главной дороге, поэтому при движении прямо должны уступить дорогу только автобусу, так как автобус приближается справа.</p>","image":"assets/adrive-questions/q113305801.jpg"},{"id":113305802,"themeId":3,"group":1133058,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить в показанной ситуации, поворачивая налево на перекрёстке?","a":["Уступить дорогу только автобусу.","Уступить дорогу только колёсному трактору.","Уступить дорогу только грузовому автомобилю.","Уступить дорогу только автобусу и колёсному трактору.","Уступить дорогу всем транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы вместе с автобусом находитесь на главной дороге, поэтому при повороте налево необходимо уступить дорогу только автобусу, так как автобус приближается к перекрёстку справа.</p>","image":"assets/adrive-questions/q113305802.jpg"},{"id":113305901,"themeId":3,"group":1133059,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только белому трамваю.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только белому и жёлтому трамваям.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу всем трамваям."],"c":2,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым и белым трамваем находится на главной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу только белому и жёлтому трамваям.</p>","image":"assets/adrive-questions/q113305901.jpg"},{"id":113305902,"themeId":3,"group":1133059,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только белому и жёлтому трамваям.","Должен уступить дорогу только белому и красному трамваям.","Должен уступить дорогу жёлтому и красному трамваям.","Должен уступить дорогу всем трамваям."],"c":3,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым и красным трамваем находится на главной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу только красному и жёлтому трамваям.</p>","image":"assets/adrive-questions/q113305902.jpg"},{"id":113306001,"themeId":3,"group":1133060,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только белому и жёлтому трамваям.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу всем трамваям."],"c":4,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым и белым трамваем находится на второстепенной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу всем трамваям.</p>","image":"assets/adrive-questions/q113306001.jpg"},{"id":113306002,"themeId":3,"group":1133060,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только белому трамваю.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только белому и жёлтому трамваям.","Должен уступить дорогу только белому и красному трамваям.","Должен уступить дорогу всем трамваям."],"c":4,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым и красным трамваем находится на второстепенной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу всем трамваям.</p>","image":"assets/adrive-questions/q113306002.jpg"},{"id":113306101,"themeId":3,"group":1133061,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":2,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с грузовым автомобилем и жёлтым трамваем находятся на второстепенной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу только жёлтому и красному трамваям, так как в равных условиях трамвай пользуется преимуществом. Водитель грузового автомобиля должен уступить дорогу также и легковому автомобилю, приближающемуся справа.</p>","image":"assets/adrive-questions/q113306101.jpg"},{"id":113306102,"themeId":3,"group":1133061,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только грузовому автомобилю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":4,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым и красным трамваями находятся на второстепенной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу всем транспортным средствам, в том числе жёлтому и красному трамваям, так как в равных условиях трамвай пользуется преимуществом.</p>","image":"assets/adrive-questions/q113306102.jpg"},{"id":113306201,"themeId":3,"group":1133062,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с грузовым автомобилем и жёлтым трамваем находится на главной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу только жёлтому трамваю, так как в равных условиях трамвай пользуется преимуществом, а грузовой автомобиль приближается к перекрёстку слева.</p>","image":"assets/adrive-questions/q113306201.jpg"},{"id":113306202,"themeId":3,"group":1133062,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль и жёлтый трамвай находятся на главной дороге, поэтому при движении прямо водитель автомобиля должен уступить дорогу только жёлтому трамваю, так как в равных условиях трамвай пользуется преимуществом.</p>","image":"assets/adrive-questions/q113306202.jpg"},{"id":113306301,"themeId":3,"group":1133063,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":1,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль и жёлтый трамвай находятся на главной дороге, поэтому при движении прямо водитель легкового автомобиля должен уступить дорогу только жёлтому трамваю, так как в равных условиях трамвай пользуется преимуществом.</p>","image":"assets/adrive-questions/q113306301.jpg"},{"id":113306302,"themeId":3,"group":1133063,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Имеет преимущество.","Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только жёлтому трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":0,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с грузовым автомобилем находятся на главной дороге, поэтому водитель легкового автомобиля при движении прямо имеет преимущество, так как находится справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113306302.jpg"},{"id":113306401,"themeId":3,"group":1133064,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу красному трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":2,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с грузовым автомобилем находятся на второстепенной дороге, поэтому водитель легкового автомобиля при движении прямо имеет преимущество только перед грузовым автомобилем, так как находится справа от него, при этом водитель легкового автомобиля должен уступить дорогу обоим трамваям.</p>","image":"assets/adrive-questions/q113306401.jpg"},{"id":113306402,"themeId":3,"group":1133064,"chapter":87,"chapters":[87],"q":"В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) при движении прямо водитель легкового автомобиля:","a":["Должен уступить дорогу только жёлтому трамваю.","Должен уступить дорогу только красному трамваю.","Должен уступить дорогу только жёлтому и красному трамваям.","Должен уступить дорогу только красному трамваю и грузовому автомобилю.","Должен уступить дорогу всем транспортным средствам."],"c":4,"e":"<p>В показанной ситуации (на светофоре включён жёлтый мигающий сигнал) легковой автомобиль вместе с жёлтым трамваем находятся на второстепенной дороге, поэтому при движении прямо должен уступить дорогу всем транспортным средствам, находящимся на главной дороге, и жёлтому трамваю, так как в равных условиях трамвай пользуется преимуществом.</p>","image":"assets/adrive-questions/q113306402.jpg"},{"id":113306501,"themeId":3,"group":1133065,"chapter":87,"chapters":[87],"q":"Имеете ли Вы преимущество в показанной ситуации, если намерены повернуть на перекрёстке направо?","a":["Да, имеете преимущество.","Нет, обязаны уступить дорогу грузовому автомобилю."],"c":0,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на равнозначных дорогах, поэтому имеете преимущество, так как находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113306501.jpg"},{"id":113306502,"themeId":3,"group":1133065,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с грузовым автомобилем находятся на равнозначных дорогах, поэтому при повороте налево водитель легкового автомобиля обязан уступить дорогу грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113306502.jpg"},{"id":113306601,"themeId":3,"group":1133066,"chapter":87,"chapters":[87],"q":"Двигаясь прямо на перекрёстке, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу колёсному трактору."],"c":1,"e":"<p>В показанной ситуации Вы вместе с колёсным трактором находитесь на равнозначных дорогах, поэтому обязаны уступить дорогу колёсному трактору, так как колёсный трактор приближается справа.</p>","image":"assets/adrive-questions/q113306601.jpg"},{"id":113306602,"themeId":3,"group":1133066,"chapter":87,"chapters":[87],"q":"Двигаясь прямо на перекрёстке, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу колёсному трактору."],"c":0,"e":"<p>В показанной ситуации Вы вместе с колёсным трактором находитесь на равнозначных дорогах, поэтому имеете преимущество, так как Вы находитесь справа от колёсного трактора.</p>","image":"assets/adrive-questions/q113306602.jpg"},{"id":113306701,"themeId":3,"group":1133067,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации, управляя легковым автомобилем:","a":["Имеете преимущество.","Обязаны уступить дорогу только колёсному трактору.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы вместе с колёсным трактором и грузовым автомобилем находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу только колёсному трактору, так как колёсный трактор приближается справа, а Вы в свою очередь находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113306701.jpg"},{"id":113306702,"themeId":3,"group":1133067,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только колёсному трактору.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на главной дороге, поэтому при повороте налево обязаны уступить дорогу только грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113306702.jpg"},{"id":113306901,"themeId":3,"group":1133069,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с грузовым автомобилем находятся на равнозначных дорогах, поэтому при повороте налево он обязан уступить дорогу грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113306901.jpg"},{"id":113306902,"themeId":3,"group":1133069,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только автобусу.","Обязан уступить дорогу только грузовому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем и автобусом находятся на равнозначной дороге, поэтому при повороте налево водитель легкового автомобиля обязан уступить дорогу только грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113306902.jpg"},{"id":113307001,"themeId":3,"group":1133070,"chapter":87,"chapters":[87],"q":"Поворачивая налево на перекрёстке, Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу только автобусу, так как автобус приближается справа.</p>","image":"assets/adrive-questions/q113307001.jpg"},{"id":113307101,"themeId":3,"group":1133071,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу справа.","Обязаны уступить дорогу только грузовому автомобилю слева.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу только автобусу, так как автобус приближается справа.</p>","image":"assets/adrive-questions/q113307101.jpg"},{"id":113307102,"themeId":3,"group":1133071,"chapter":87,"chapters":[87],"q":"При движении прямо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при движении прямо обязаны уступить дорогу только автобусу, так как автобус приближается справа.</p>","image":"assets/adrive-questions/q113307102.jpg"},{"id":113307201,"themeId":3,"group":1133072,"chapter":87,"chapters":[87],"q":"При движении прямо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при движении прямо имеете преимущество, так как Вы приближаетесь к перекрёстку справа от автобуса, а грузовой автомобиль поворачивает налево.</p>","image":"assets/adrive-questions/q113307201.jpg"},{"id":113307202,"themeId":3,"group":1133072,"chapter":87,"chapters":[87],"q":"При повороте направо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":0,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при повороте налево имеете преимущество, так как Вы приближаетесь к перекрёстку справа от автобуса, а грузовой автомобиль поворачивает налево.</p>","image":"assets/adrive-questions/q113307202.jpg"},{"id":113307301,"themeId":3,"group":1133073,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только автобусу.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":2,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и автобусом находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу только грузовому автомобилю, который поворачивает направо. По отношению к автобусу Вы пользуетесь преимуществом, так как приближаетесь к перекрёстку справа от него.</p>","image":"assets/adrive-questions/q113307301.jpg"},{"id":113307401,"themeId":3,"group":1133074,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только самоходной машине.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и самоходной машиной находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу грузовому автомобилю, движущемуся прямо, и самоходной машине, которая приближается справа.</p>","image":"assets/adrive-questions/q113307401.jpg"},{"id":113307402,"themeId":3,"group":1133074,"chapter":87,"chapters":[87],"q":"При повороте налево Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу только самоходной машине.","Обязаны уступить дорогу только грузовому автомобилю.","Обязаны уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем и самоходной машиной находитесь на равнозначных дорогах, поэтому при повороте налево обязаны уступить дорогу грузовому автомобилю, поворачивающему направо, и самоходной машине, которая приближается справа.</p>","image":"assets/adrive-questions/q113307402.jpg"},{"id":113307631,"themeId":3,"group":1133076,"chapter":87,"chapters":[87],"q":"В показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем находятся в равных условиях, поэтому водитель легкового автомобиля обязан уступить дорогу грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113307631.jpg"},{"id":113307632,"themeId":3,"group":1133076,"chapter":87,"chapters":[87],"q":"Подъехав к перекрёстку с круговым движением, Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу грузовому автомобилю."],"c":0,"e":"<p>В показанной ситуации Вы приближаетесь к перекрёстку равнозначных дорог, поэтому имеете преимущество, так как Вы находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113307632.jpg"},{"id":113307701,"themeId":3,"group":1133077,"chapter":87,"chapters":[87],"q":"При повороте направо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только колёсному трактору.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации все ТС находятся перед перекрёстком равнозначных дорог, поэтому водитель легкового автомобиля при повороте направо обязан уступить дорогу только трамваю, так как трамвай в равных условиях пользуется преимуществом. Водитель колёсного трактора обязан уступить дорогу легковому автомобилю, приближающемуся справа.</p>","image":"assets/adrive-questions/q113307701.jpg"},{"id":113307702,"themeId":3,"group":1133077,"chapter":87,"chapters":[87],"q":"При повороте направо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только грузовому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с грузовым автомобилем и трамваем находятся на главной дороге, поэтому при повороте направо обязан уступить дорогу только трамваю, так как трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113307702.jpg"},{"id":113307801,"themeId":3,"group":1133078,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только грузовому автомобилю.","Обязан уступить дорогу обоим транспортным средствам."],"c":1,"e":"<p>В показанной ситуации легковой автомобиль вместе с грузовым автомобилем и трамваем находятся перед перекрёстком равнозначных дорог, поэтому при повороте налево водитель легкового автомобиля обязан уступить дорогу только трамваю, так как трамвай в равных условиях пользуется преимуществом. Водитель грузового автомобиля обязан уступить дорогу легковому автомобилю, приближающемуся справа.</p>","image":"assets/adrive-questions/q113307801.jpg"},{"id":113307802,"themeId":3,"group":1133078,"chapter":87,"chapters":[87],"q":"При повороте налево в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только трамваю.","Обязан уступить дорогу только колёсному трактору.","Обязан уступить дорогу обоим транспортным средствам."],"c":3,"e":"<p>В показанной ситуации легковой автомобиль вместе с колёсным трактором и трамваем находятся перед перекрёстком равнозначных дорог, поэтому при повороте налево водитель легкового автомобиля обязан уступить дорогу всем встречным транспортным средствам, движущимся прямо или поворачивающим направо.</p>","image":"assets/adrive-questions/q113307802.jpg"},{"id":113308001,"themeId":3,"group":1133080,"chapter":87,"chapters":[87],"q":"При движении прямо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу колёсному трактору."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с колёсным трактором находятся на второстепенной дороге, поэтому при движении прямо он имеет преимущество, так как колёсный трактор при повороте налево или развороте обязан уступить дорогу ТС двигающимся в прямом направлении.</p>","image":"assets/adrive-questions/q113308001.jpg"},{"id":113308002,"themeId":3,"group":1133080,"chapter":87,"chapters":[87],"q":"При повороте направо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу колёсному трактору."],"c":0,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с колёсным трактором находятся на второстепенной дороге, поэтому при повороте направо он имеет преимущество, так как колёсный трактор при повороте налево обязан уступить дорогу ТС двигающимся направо.</p>","image":"assets/adrive-questions/q113308002.jpg"},{"id":113308101,"themeId":3,"group":1133081,"chapter":87,"chapters":[87],"q":"При движении прямо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу грузовому автомобилю."],"c":0,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на второстепенной дороге, поэтому при движении прямо имеете преимущество, так как Вы находитесь справа от грузового автомобиля.</p>","image":"assets/adrive-questions/q113308101.jpg"},{"id":113308102,"themeId":3,"group":1133081,"chapter":87,"chapters":[87],"q":"При движении прямо Вы в показанной ситуации:","a":["Имеете преимущество.","Обязаны уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>В показанной ситуации Вы вместе с грузовым автомобилем находитесь на второстепенной дороге, поэтому при движении прямо обязаны уступить дорогу грузовому автомобилю, так как грузовой автомобиль приближается справа.</p>","image":"assets/adrive-questions/q113308102.jpg"},{"id":113308201,"themeId":3,"group":1133082,"chapter":87,"chapters":[87],"q":"При движении прямо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу трамваю."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с трамваем находятся на главной дороге, поэтому при движении прямо обязан уступить дорогу трамваю, так как трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113308201.jpg"},{"id":113308202,"themeId":3,"group":1133082,"chapter":87,"chapters":[87],"q":"При движении прямо в показанной ситуации водитель легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу трамваю."],"c":1,"e":"<p>В показанной ситуации водитель легкового автомобиля вместе с трамваем находятся на главной дороге, поэтому при движении прямо обязан уступить дорогу трамваю, так как трамвай в равных условиях пользуется преимуществом.</p>","image":"assets/adrive-questions/q113308202.jpg"},{"id":113308352,"themeId":3,"group":1133083,"chapter":87,"chapters":[87],"q":"Как Вам следует поступить при повороте налево на необозначенном перекрёстке, двигаясь по дороге с усовершенствованным покрытием?","a":["Пользуясь преимуществом, первым проехать перекрёсток.","Уступить дорогу колёсному трактору, приближающемуся по дороге с гравийным покрытием."],"c":0,"e":"<p>Дорога с усовершенствованным покрытием является главной по отношению к дороге без такого покрытия.</p> <p>Двигаясь по главной дороге, Вы имеете преимущество перед транспортными средствами, выезжающими со второстепенных дорог.</p>","image":"assets/adrive-questions/q113308352.jpg"},{"id":113308501,"themeId":3,"group":1133085,"chapter":87,"chapters":[87],"q":"Если в тёмное время суток водитель не может определить последовательность проезда перекрёстка из-за невозможности распознать наличие покрытия на проезжей части дороги, как он должен действовать?","a":["Так, как если находится на главной дороге.","Так, как если находится на второстепенной дороге.","Так, как если находится на перекрёстке равнозначных дорог."],"c":1,"e":"<p>Если водитель не может определить последовательность проезда перекрёстка из-за невозможности распознать наличие покрытия на проезжей части дороги (тёмное время суток, грязь, снег и прочее), то он должен действовать так, как если бы находился на второстепенной дороге.</p>","image":"assets/adrive-questions/q113308501.jpg"},{"id":113308502,"themeId":3,"group":1133085,"chapter":87,"chapters":[87],"q":"Если в светлое время суток водитель не может определить последовательность проезда перекрёстка из-за невозможности распознать наличие покрытия на проезжей части дороги из-за выпавшего снега, как он должен действовать?","a":["Так, как если находится на главной дороге.","Так, как если находится на второстепенной дороге.","Так, как если находится на перекрёстке равнозначных дорог."],"c":1,"e":"<p>Если водитель не может определить последовательность проезда перекрёстка из-за невозможности распознать наличие покрытия на проезжей части дороги (тёмное время суток, грязь, снег и прочее), то он должен действовать так, как если бы находился на второстепенной дороге.</p>","image":null}];